module types

import v2.ast
import v2.token

fn test_collect_autofree_facts_enables_pipeline_without_releases() {
	mut env := Environment.new()
	mut strings := []string{}
	strings << 'main'
	flat := ast.FlatAst{
		nodes:   []ast.FlatNode{len: 2}
		edges:   []ast.FlatEdge{len: 1}
		strings: strings
	}
	env.reset_autofree_facts_for_flat(&flat)
	env.collect_autofree_facts_from_flat(&flat)
	assert env.autofree_pipeline.enabled
	assert env.autofree_pipeline.flat_nodes == 2
	assert env.autofree_pipeline.flat_edges == 1
	assert env.autofree_pipeline.flat_strings == 1
	assert env.autofree_bindings_by_fn_key.len == 0
	assert env.autofree_fresh_locals_by_fn_key.len == 0
	assert env.autofree_move_proofs_by_fn_key.len == 0
	assert env.autofree_natural_release_candidates_by_fn_key.len == 0
	assert env.autofree_release_plans_by_fn_key.len == 0
	assert env.autofree_release_preflights_by_fn_key.len == 0
	assert env.autofree_release_insertion_points_by_fn_key.len == 0
	assert env.autofree_transfers_by_fn_key.len == 0
	assert env.autofree_release_eligibility_by_fn_key.len == 0
	assert env.autofree_releases_by_fn_key.len == 0
	assert env.autofree_helper_roots.len == 0
}

fn test_collect_autofree_parameter_bindings_collects_function_parameters() {
	mut env := Environment.new()
	flat := autofree_test_flat_with_function_boundary()
	mut store_scope := new_scope(unsafe { nil })
	map_type := Type(Map{
		key_type:   Type(string_)
		value_type: Type(int_)
	})
	store_scope.insert('items', object_from_type(map_type))
	store_scope.insert('count', object_from_type(Type(int_)))
	env.set_fn_scope('main', 'store', store_scope)

	autofree_test_collect_parameter_bindings(mut env, &flat)

	assert 'store' in env.autofree_bindings_by_fn_key
	assert 'main__store' !in env.autofree_bindings_by_fn_key
	store_bindings := env.autofree_bindings_by_fn_key['store']
	assert store_bindings.len == 2
	items := autofree_test_binding_by_name(store_bindings, 'items')
	assert items.fn_key == 'store'
	assert items.fn_name == 'store'
	assert items.storage == .parameter
	assert items.resource == .map_container
	assert items.shape.kind == .map_
	assert items.shape.map_container_may_need_free
	assert items.shape.map_key_kind == .string_
	assert items.shape.map_key_may_need_free
	assert items.shape.map_value_kind == .no_resource
	assert !items.shape.map_value_may_need_free
	assert items.state == .ambiguous_no_free
	count := autofree_test_binding_by_name(store_bindings, 'count')
	assert count.fn_key == 'store'
	assert count.storage == .parameter
	assert count.resource == .no_resource
	assert count.shape.kind == .no_resource
	assert count.state == .copy_no_resource
	assert env.autofree_fresh_locals_by_fn_key.len == 0
	assert env.autofree_move_proofs_by_fn_key.len == 0
	assert env.autofree_natural_release_candidates_by_fn_key.len == 0
	assert env.autofree_release_plans_by_fn_key.len == 0
	assert env.autofree_release_preflights_by_fn_key.len == 0
	assert env.autofree_release_insertion_points_by_fn_key.len == 0
	assert env.autofree_transfers_by_fn_key.len == 0
	assert env.autofree_release_eligibility_by_fn_key.len == 0
	assert env.autofree_releases_by_fn_key.len == 0
	assert env.autofree_helper_roots.len == 0
}

fn test_collect_autofree_facts_collects_inert_decl_transfer_fixture() {
	mut env := Environment.new()
	flat := autofree_test_flat_with_direct_ident_decl_transfer()
	autofree_test_add_scope_with_string_vars(mut env, 'copy_value', ['source', 'target'])
	env.set_expr_type(autofree_test_lhs_pos, Type(string_))
	env.set_expr_type(autofree_test_rhs_pos, Type(string_))

	env.collect_autofree_facts_from_flat(&flat)

	assert 'copy_value' in env.autofree_bindings_by_fn_key
	bindings := env.autofree_bindings_by_fn_key['copy_value']
	assert bindings.len == 1
	source := autofree_test_binding_by_name(bindings, 'source')
	assert source.storage == .parameter
	assert source.state == .ambiguous_no_free
	assert source.shape.kind == .string_
	assert 'copy_value' in env.autofree_transfers_by_fn_key
	transfers := env.autofree_transfers_by_fn_key['copy_value']
	assert transfers.len == 1
	transfer := transfers[0]
	assert transfer.kind == .decl
	assert transfer.action == .ambiguous_no_free
	assert transfer.from_endpoint.storage == .parameter
	assert transfer.from_endpoint.name == 'source'
	assert transfer.to_endpoint.storage == .local
	assert transfer.to_endpoint.name == 'target'
	assert env.autofree_fresh_locals_by_fn_key.len == 0
	autofree_test_assert_not_release_eligible(env, 'copy_value', ['target'])
}

fn test_collect_autofree_facts_keeps_fresh_array_insertion_point_chain_enabled() {
	mut env := Environment.new()
	flat := autofree_test_flat_with_fresh_array_local('fresh_array_chain', autofree_test_empty_array_expr('int',
		autofree_test_rhs_pos), []ast.Stmt{})
	array_type := Type(Array{
		elem_type: Type(int_)
	})
	env.set_expr_type(autofree_test_lhs_pos, array_type)
	env.set_expr_type(autofree_test_rhs_pos, array_type)

	env.collect_autofree_facts_from_flat(&flat)

	assert 'fresh_array_chain' in env.autofree_release_insertion_points_by_fn_key
	assert env.autofree_release_insertion_points_by_fn_key['fresh_array_chain'].len == 1
	assert env.autofree_bindings_by_fn_key.len == 0
	assert env.autofree_transfers_by_fn_key.len == 0
	assert env.autofree_release_eligibility_by_fn_key.len == 0
	assert env.autofree_releases_by_fn_key.len == 0
	assert env.autofree_helper_roots.len == 0
}

struct AutofreeScalarArrayCloneCleanupMiddleRejectCase {
	name string
	stmt ast.Stmt
}

struct AutofreeScalarArrayCloneCleanupTypeRejectCase {
	name           string
	elem_type_name string
	array_type     Type
}

struct AutofreeScalarArrayCloneCleanupLoweredRejectCase {
	name       string
	source_rhs ast.Expr
	final_rhs  ast.Expr
}

struct AutofreeFreshArrayFinalCloneRejectCase {
	name           string
	elem_type_name string
	rhs            ast.Expr
	array_type     Type
}

struct AutofreeCapOnlyFreshArrayRejectCase {
	name         string
	rhs          ast.Expr
	array_type   Type
	cap_type     Type
	set_cap_type bool
	params       []ast.Parameter
	scope_vars   map[string]Type
	extra_stmts  []ast.Stmt
	mut_lhs      bool
}

struct AutofreeLenOnlyFreshArrayRejectCase {
	name         string
	rhs          ast.Expr
	array_type   Type
	len_type     Type
	set_len_type bool
	params       []ast.Parameter
	scope_vars   map[string]Type
	extra_stmts  []ast.Stmt
	mut_lhs      bool
}

fn test_collect_autofree_facts_collects_scalar_array_clone_cleanup_after_final_clone_assignment() {
	mut env := Environment.new()
	fn_name := 'scalar_array_clone_cleanup'
	flat := autofree_test_flat_with_scalar_array_clone_cleanup(fn_name, [
		autofree_test_scalar_array_clone_element_update_stmt(),
	])
	array_type := autofree_test_move_proof_array_type()
	autofree_test_prepare_scalar_array_clone_cleanup_env(mut env, fn_name, array_type)

	env.collect_autofree_facts_from_flat(&flat)

	autofree_test_assert_scalar_array_clone_cleanup(env, flat, fn_name, array_type)
}

