fn test_collect_autofree_prior_local_parameter_field_array_push_transfers_skip_bad_body_shapes() {
	array_type := autofree_test_move_proof_array_type()
	slots_type := autofree_test_array_element_root_type(array_type)
	holder_type := autofree_test_slots_holder_type(slots_type)
