		second_alias,
		push,
	])
	array_type := autofree_test_move_proof_array_type()
	root_type := autofree_test_array_element_root_type(array_type)
	autofree_test_prepare_prior_local_parameter_array_push_env(mut env, fn_name, root_type,
		array_type, array_type, array_type, array_type)
