fn test_collect_autofree_prior_local_parameter_array_push_transfers_skip_bad_body_shapes() {
	alias := autofree_test_prior_local_parameter_array_push_alias_decl('tmp', autofree_test_ident_expr('source',
		autofree_test_rhs_pos))
	push := autofree_test_prior_local_parameter_array_push_stmt_with_names('root', autofree_test_ident_expr('tmp',
		autofree_test_second_rhs_pos))
	extra := autofree_test_decl_assign_stmt(autofree_test_ident_expr('count',
		autofree_test_other_lhs_pos), autofree_test_int_expr('1', autofree_test_other_rhs_pos))
	method_decl := ast.FnDecl{
		is_method: true
		receiver:  autofree_test_mut_param_at('receiver', 'Receiver', autofree_test_other_lhs_pos)
		name:      'prior_local_parameter_array_push_method'
		typ:       ast.FnType{
			params: autofree_test_prior_local_parameter_array_push_params('[][]int', '[]int')
		}
		stmts:     [alias, push]
	}
	nested_block := ast.BlockStmt{
		stmts: [alias, push]
	}
	autofree_test_assert_prior_local_parameter_array_push_flat_rejected('prior_local_parameter_array_push_extra_statement', autofree_test_flat_with_free_function('prior_local_parameter_array_push_extra_statement', autofree_test_prior_local_parameter_array_push_params('[][]int',
		'[]int'), [
		alias,
		extra,
		push,
	]))
	autofree_test_assert_prior_local_parameter_array_push_flat_rejected('prior_local_parameter_array_push_method', autofree_test_flat_with_stmts([
		ast.Stmt(method_decl),
	]))
	autofree_test_assert_prior_local_parameter_array_push_flat_rejected('prior_local_parameter_array_push_nested_body', autofree_test_flat_with_free_function('prior_local_parameter_array_push_nested_body', autofree_test_prior_local_parameter_array_push_params('[][]int',
		'[]int'), [
		ast.Stmt(nested_block),
	]))
}

