fn autofree_test_assert_for_in_field_array_push_named_collects(fn_name string, root_name string, field_name string, iterable_name string, iterator_name string, params []ast.Parameter) {
	mut env := Environment.new()
	flat := autofree_test_flat_with_for_in_field_array_push_named(fn_name, params, iterator_name,
		iterable_name, [
		autofree_test_for_in_field_array_push_stmt_with_names(root_name, field_name, autofree_test_ident_expr(iterator_name,
			autofree_test_second_rhs_pos)),
	])
	array_type := autofree_test_move_proof_array_type()
	field_type := autofree_test_array_element_root_type(array_type)
	iterable_type := autofree_test_array_element_root_type(array_type)
	holder_type := autofree_test_named_field_holder_type(field_name, field_type)
	mut var_types := map[string]Type{}
	var_types[root_name] = holder_type
	var_types[iterable_name] = iterable_type
	var_types[iterator_name] = array_type
	if params.len > 2 {
		var_types['extra'] = Type(int_)
	}
	autofree_test_add_scope_with_var_types(mut env, fn_name, var_types)
	autofree_test_set_for_in_field_array_push_expr_types(mut env, holder_type, field_type,
		iterable_type, array_type, array_type)

	autofree_test_collect_array_push_transfers_and_eligibility(mut env, &flat)

	autofree_test_assert_for_in_field_array_push_transfer_with_names(env, flat, fn_name,
		array_type, .no_resource, root_name, field_name, iterable_name, iterator_name)
}

