fn test_collect_autofree_for_in_direct_array_push_transfers_skip_bad_loop_bodies_and_aliases() {
	push := autofree_test_for_in_direct_array_push_stmt_with_names('root', autofree_test_ident_expr('item',
		autofree_test_second_rhs_pos))
	extra := autofree_test_decl_assign_stmt(autofree_test_ident_expr('count',
		autofree_test_other_lhs_pos), autofree_test_int_expr('1', autofree_test_other_rhs_pos))
	alias := autofree_test_decl_assign_stmt(autofree_test_ident_expr('tmp', autofree_test_lhs_pos), autofree_test_ident_expr('item',
		autofree_test_rhs_pos))
	push_alias := autofree_test_for_in_direct_array_push_stmt_with_names('root', autofree_test_ident_expr('tmp',
		autofree_test_second_rhs_pos))
	first_alias := autofree_test_decl_assign_stmt(autofree_test_ident_expr('a',
		autofree_test_other_lhs_pos), autofree_test_ident_expr('item', autofree_test_other_rhs_pos))
	second_alias := autofree_test_decl_assign_stmt(autofree_test_ident_expr('tmp',
		autofree_test_lhs_pos), autofree_test_ident_expr('a', autofree_test_rhs_pos))
	nested_loop := autofree_test_for_in_direct_array_push_loop_with_names('item', 'iterable', [
		push,
	])
	nested_block := ast.BlockStmt{
		stmts: [push]
	}
	if_stmt := ast.Stmt(ast.ExprStmt{
		expr: ast.Expr(ast.IfExpr{
			cond:  autofree_test_ident_expr('ok', autofree_test_other_rhs_pos)
			stmts: [push]
			pos:   autofree_test_pos(autofree_test_other_lhs_pos)
		})
	})
	autofree_test_assert_for_in_direct_array_push_body_rejected('empty_body', []ast.Stmt{})
	autofree_test_assert_for_in_direct_array_push_body_rejected('multiple_body_statements', [
		push,
		extra,
	])
	autofree_test_assert_for_in_direct_array_push_flat_rejected('extra_statement', autofree_test_flat_with_free_function('for_in_direct_array_push_extra_statement', autofree_test_for_in_direct_array_push_params('[][]int',
		'[][]int'), [
		extra,
		autofree_test_for_in_direct_array_push_loop_with_names('item', 'iterable', [
			push,
		]),
	]))
	autofree_test_assert_for_in_direct_array_push_body_rejected('nested_loop_body', [
		nested_loop,
	])
	autofree_test_assert_for_in_direct_array_push_body_rejected('nested_block_body', [
		ast.Stmt(nested_block),
	])
	autofree_test_assert_for_in_direct_array_push_body_rejected('if_body', [if_stmt])
	autofree_test_assert_for_in_direct_array_push_body_rejected('alias_inside_loop', [
		alias,
		push_alias,
	])
	autofree_test_assert_for_in_direct_array_push_body_rejected('alias_chain_inside_loop', [
		first_alias,
		second_alias,
		push_alias,
	])
}

