fn test_collect_autofree_facts_collects_mut_empty_int_array_from_builtin_lowered_alloc() {
	mut env := Environment.new()
	flat := autofree_test_flat_with_mut_fresh_array_local('fresh_mut_builtin_array_local', autofree_test_lowered_array_alloc_expr('builtin____new_array_with_default_noscan',
		'0', '0', 'int', 'NULL', autofree_test_rhs_pos), []ast.Stmt{})
	array_type := Type(Array{
		elem_type: Type(int_)
	})
	array_type_name := array_type.name()
	env.set_expr_type(autofree_test_lhs_pos, array_type)
	env.set_expr_type(autofree_test_rhs_pos, array_type)
	lhs_id := autofree_test_node_id_by_kind_name_pos(flat, .expr_ident, 'items',
		autofree_test_lhs_pos)
	rhs_id := autofree_test_node_id_by_kind_pos(flat, .expr_call, autofree_test_rhs_pos)

	env.collect_autofree_facts_from_flat(&flat)

	assert 'fresh_mut_builtin_array_local' in env.autofree_fresh_locals_by_fn_key
	facts := env.autofree_fresh_locals_by_fn_key['fresh_mut_builtin_array_local']
	assert facts.len == 1
	fact := facts[0]
	assert fact.name == 'items'
	assert fact.node_id == lhs_id
	assert fact.endpoint.node_id == lhs_id
	assert fact.endpoint.type_name == array_type_name
	assert fact.source_endpoint.node_id == rhs_id
	assert fact.source_endpoint.reason == 'empty dynamic array literal'
	assert fact.shape.kind == .array
	assert fact.shape.target_kind == .no_resource
	assert 'fresh_mut_builtin_array_local' in env.autofree_release_insertion_points_by_fn_key
	insertion_points := env.autofree_release_insertion_points_by_fn_key['fresh_mut_builtin_array_local']
	assert insertion_points.len == 1
	assert insertion_points[0].endpoint.node_id == lhs_id
	assert insertion_points[0].source_endpoint.node_id == rhs_id
	assert insertion_points[0].plan_action == .array_container_cleanup
	assert insertion_points[0].helper_requirement == .none
	assert env.autofree_transfers_by_fn_key.len == 0
	assert env.autofree_release_eligibility_by_fn_key.len == 0
	assert env.autofree_releases_by_fn_key.len == 0
	assert env.autofree_helper_roots.len == 0
}

