		'items':  array_type
	})
	env.set_expr_type(autofree_test_second_lhs_pos, array_type)
	env.set_expr_type(autofree_test_second_rhs_pos, array_type)
	env.set_expr_type(autofree_test_lhs_pos, array_type)
	env.set_expr_type(autofree_test_rhs_pos, array_type)

	env.collect_autofree_facts_from_flat(&flat)

	assert 'fresh_array_after_transfer' in env.autofree_fresh_locals_by_fn_key
	fresh := env.autofree_fresh_locals_by_fn_key['fresh_array_after_transfer'][0]
	assert fresh.name == 'items'
	assert fresh.shape.kind == .array
	assert fresh.shape.target_kind == .no_resource
	assert 'fresh_array_after_transfer' in env.autofree_release_insertion_points_by_fn_key
	insertion_points := env.autofree_release_insertion_points_by_fn_key['fresh_array_after_transfer']
	assert insertion_points.len == 1
	assert insertion_points[0].endpoint.name == 'items'
	assert insertion_points[0].plan_action == .array_container_cleanup
	assert insertion_points[0].helper_requirement == .none
	assert 'fresh_array_after_transfer' in env.autofree_transfers_by_fn_key
	transfers := env.autofree_transfers_by_fn_key['fresh_array_after_transfer']
	assert transfers.len == 1
	transfer := transfers[0]
	assert transfer.from_endpoint.name == 'source'
	assert transfer.from_endpoint.storage == .parameter
	assert transfer.to_endpoint.name == 'copy'
	assert transfer.to_endpoint.storage == .local
	assert transfer.action == .ambiguous_no_free
	eligibility := autofree_test_release_eligibility_by_name(env.autofree_release_eligibility_by_fn_key['fresh_array_after_transfer'],
		'copy')
	assert eligibility.eligibility == .not_release_eligible
	assert eligibility.transfer_action == .ambiguous_no_free
	assert env.autofree_releases_by_fn_key.len == 0
	assert env.autofree_helper_roots.len == 0
}

