	assert 'fresh_array_after_copy_literal' in env.autofree_fresh_locals_by_fn_key
	fresh := env.autofree_fresh_locals_by_fn_key['fresh_array_after_copy_literal'][0]
	assert fresh.name == 'items'
	assert fresh.shape.kind == .array
	assert fresh.shape.target_kind == .no_resource
	assert 'fresh_array_after_copy_literal' in env.autofree_release_insertion_points_by_fn_key
	insertion_points := env.autofree_release_insertion_points_by_fn_key['fresh_array_after_copy_literal']
	assert insertion_points.len == 1
	assert insertion_points[0].endpoint.name == 'items'
	assert insertion_points[0].plan_action == .array_container_cleanup
	assert insertion_points[0].helper_requirement == .none
	assert env.autofree_transfers_by_fn_key.len == 0
	assert env.autofree_release_eligibility_by_fn_key.len == 0
	assert env.autofree_releases_by_fn_key.len == 0
	assert env.autofree_helper_roots.len == 0
}

