fn test_collect_autofree_natural_release_candidates_skip_duplicate_names() {
	shape := autofree_test_move_proof_array_shape()
	type_name := autofree_test_move_proof_array_type().name()
	proof := autofree_test_natural_release_move_proof(autofree_test_move_proof_source_endpoint(2,
		11, 2, 11, shape, type_name), autofree_test_move_proof_target_endpoint(1, 10, 1, 10, shape,
		type_name), shape, type_name, .owned_unique, .array_value, .fresh_local_binding, 1, 10)
	mut env := Environment.new()
	env.autofree_move_proofs_by_fn_key = map[string][]AutofreeMoveProofFact{}
	env.autofree_natural_release_candidates_by_fn_key = map[string][]AutofreeNaturalReleaseCandidateFact{}
	env.autofree_move_proofs_by_fn_key['make_items'] = [proof, proof]

	env.collect_autofree_natural_release_candidates_from_move_proofs()

	if 'make_items' in env.autofree_natural_release_candidates_by_fn_key {
		assert env.autofree_natural_release_candidates_by_fn_key['make_items'].len == 0
	}
	assert env.autofree_transfers_by_fn_key.len == 0
	assert env.autofree_release_eligibility_by_fn_key.len == 0
	assert env.autofree_releases_by_fn_key.len == 0
	assert env.autofree_helper_roots.len == 0
}

