fn test_collect_autofree_decl_transfers_collects_direct_ident_decl_transfer() {
	mut env := Environment.new()
	flat := autofree_test_flat_with_direct_ident_decl_transfer()
	autofree_test_add_scope_with_string_vars(mut env, 'copy_value', ['source', 'target'])
	env.set_expr_type(autofree_test_lhs_pos, Type(string_))
	env.set_expr_type(autofree_test_rhs_pos, Type(string_))
	source_param_id := autofree_test_node_id_by_kind_name_pos(flat, .aux_parameter, 'source',
		autofree_test_source_param_pos)
	source_ident_id := autofree_test_node_id_by_kind_name_pos(flat, .expr_ident, 'source',
		autofree_test_rhs_pos)
	target_ident_id := autofree_test_node_id_by_kind_name_pos(flat, .expr_ident, 'target',
		autofree_test_lhs_pos)

	autofree_test_collect_decl_transfers_and_eligibility(mut env, &flat)

	assert 'copy_value' in env.autofree_transfers_by_fn_key
	transfers := env.autofree_transfers_by_fn_key['copy_value']
	assert transfers.len == 1
	transfer := transfers[0]
	assert transfer.fn_key == 'copy_value'
	assert transfer.fn_name == 'copy_value'
	assert transfer.kind == .decl
	assert transfer.action == .ambiguous_no_free
	assert transfer.from_endpoint.storage == .parameter
	assert transfer.from_endpoint.root_storage == .parameter
	assert transfer.from_endpoint.root_name == 'source'
	assert transfer.from_endpoint.name == 'source'
	assert transfer.from_endpoint.root_node_id == source_param_id
	assert transfer.from_endpoint.root_pos_id == autofree_test_source_param_pos
	assert transfer.from_endpoint.node_id == source_ident_id
	assert transfer.from_endpoint.pos_id == autofree_test_rhs_pos
	assert transfer.from_endpoint.path.len == 0
	assert transfer.from_endpoint.has_type
	assert transfer.from_endpoint.shape.kind == .string_
	assert transfer.to_endpoint.storage == .local
	assert transfer.to_endpoint.root_storage == .local
	assert transfer.to_endpoint.root_name == 'target'
	assert transfer.to_endpoint.name == 'target'
	assert transfer.to_endpoint.root_node_id == target_ident_id
	assert transfer.to_endpoint.root_pos_id == autofree_test_lhs_pos
	assert transfer.to_endpoint.node_id == target_ident_id
	assert transfer.to_endpoint.pos_id == autofree_test_lhs_pos
	assert transfer.to_endpoint.path.len == 0
	assert transfer.to_endpoint.has_type
	assert transfer.to_endpoint.shape.kind == .string_
	assert env.autofree_move_proofs_by_fn_key.len == 0
	autofree_test_assert_not_release_eligible(env, 'copy_value', ['target'])
}

