fn test_collect_autofree_decl_transfers_collect_local_source_decl_transfer() {
	mut env := Environment.new()
	flat := autofree_test_flat_with_local_source_chain('local_source_chain', 'string')
	autofree_test_add_scope_with_string_vars(mut env, 'local_source_chain', ['source', 'a', 'b'])
	env.set_expr_type(autofree_test_lhs_pos, Type(string_))
	env.set_expr_type(autofree_test_rhs_pos, Type(string_))
	env.set_expr_type(autofree_test_second_lhs_pos, Type(string_))
	env.set_expr_type(autofree_test_second_rhs_pos, Type(string_))
	a_decl_id := autofree_test_node_id_by_kind_name_pos(flat, .expr_ident, 'a',
		autofree_test_lhs_pos)
	a_use_id := autofree_test_node_id_by_kind_name_pos(flat, .expr_ident, 'a',
		autofree_test_second_rhs_pos)
	b_decl_id := autofree_test_node_id_by_kind_name_pos(flat, .expr_ident, 'b',
		autofree_test_second_lhs_pos)

	autofree_test_collect_decl_transfers_and_eligibility(mut env, &flat)

	assert 'local_source_chain' in env.autofree_transfers_by_fn_key
	transfers := env.autofree_transfers_by_fn_key['local_source_chain']
	assert transfers.len == 2
	second := autofree_test_transfer_by_to_name(transfers, 'b')
	assert second.action == .ambiguous_no_free
	assert second.from_endpoint.storage == .local
	assert second.from_endpoint.root_storage == .local
	assert second.from_endpoint.root_name == 'a'
	assert second.from_endpoint.name == 'a'
	assert second.from_endpoint.root_node_id == a_decl_id
	assert second.from_endpoint.root_pos_id == autofree_test_lhs_pos
	assert second.from_endpoint.node_id == a_use_id
	assert second.from_endpoint.pos_id == autofree_test_second_rhs_pos
	assert second.from_endpoint.path.len == 0
	assert second.to_endpoint.storage == .local
	assert second.to_endpoint.root_storage == .local
	assert second.to_endpoint.root_name == 'b'
	assert second.to_endpoint.name == 'b'
	assert second.to_endpoint.root_node_id == b_decl_id
	assert second.to_endpoint.root_pos_id == autofree_test_second_lhs_pos
	assert second.to_endpoint.node_id == b_decl_id
	assert second.to_endpoint.pos_id == autofree_test_second_lhs_pos
	assert second.to_endpoint.path.len == 0
	assert env.autofree_move_proofs_by_fn_key.len == 0
	autofree_test_assert_not_release_eligible(env, 'local_source_chain', ['a', 'b'])
}

