	facts := env.autofree_release_eligibility_by_fn_key['synthetic_local_move']
	assert facts.len == 1
	fact := facts[0]
	assert fact.name == 'items'
	assert fact.transfer_action == .move
	assert fact.endpoint.storage == .local
	assert fact.endpoint.root_storage == .local
	assert fact.endpoint.state == .owned_unique
	assert fact.endpoint.shape.needs_autofree()
	assert fact.eligibility == .release_eligible
	autofree_test_assert_no_releases_or_helper_roots(env)
}

