fn test_collect_autofree_release_eligibility_keeps_inert_transfer_actions_not_release_eligible() {
	int_type := Type(int_)
	copy_shape := autofree_resource_shape_for_type(int_type)
	pointer_type := Type(Pointer{
		base_type: Type(string_)
	})
	borrow_shape := autofree_resource_shape_for_type(pointer_type)
	array_type := autofree_test_move_proof_array_type()
	ambiguous_shape := autofree_test_move_proof_array_shape()
	transfers := [
		autofree_test_synthetic_transfer('synthetic_inert_actions', 'copied_count', .decl,
			.copy_no_resource, autofree_test_synthetic_transfer_endpoint('copied_count',
			'copied_count', .local, .local, int_type, copy_shape, .copy_no_resource,
			'synthetic copy target')),
		autofree_test_synthetic_transfer('synthetic_inert_actions', 'borrowed_pointer', .decl,
			.borrow_no_free, autofree_test_synthetic_transfer_endpoint('borrowed_pointer',
			'borrowed_pointer', .local, .local, pointer_type, borrow_shape, .borrowed_no_free,
			'synthetic borrow target')),
		autofree_test_synthetic_transfer('synthetic_inert_actions', 'ambiguous_items', .decl,
			.ambiguous_no_free, autofree_test_synthetic_transfer_endpoint('ambiguous_items',
			'ambiguous_items', .local, .local, array_type, ambiguous_shape, .ambiguous_no_free,
			'synthetic ambiguous target')),
	]

	env := autofree_test_collect_release_eligibility_for_synthetic_transfers('synthetic_inert_actions',
		transfers)

	assert 'synthetic_inert_actions' in env.autofree_release_eligibility_by_fn_key
	facts := env.autofree_release_eligibility_by_fn_key['synthetic_inert_actions']
	assert facts.len == 3
	copy_fact := autofree_test_release_eligibility_by_name(facts, 'copied_count')
	assert copy_fact.transfer_action == .copy_no_resource
	assert copy_fact.endpoint.storage == .local
	assert copy_fact.eligibility == .not_release_eligible
	borrow_fact := autofree_test_release_eligibility_by_name(facts, 'borrowed_pointer')
	assert borrow_fact.transfer_action == .borrow_no_free
	assert borrow_fact.endpoint.storage == .local
	assert borrow_fact.eligibility == .not_release_eligible
	ambiguous_fact := autofree_test_release_eligibility_by_name(facts, 'ambiguous_items')
	assert ambiguous_fact.transfer_action == .ambiguous_no_free
	assert ambiguous_fact.endpoint.storage == .local
	assert ambiguous_fact.eligibility == .not_release_eligible
	autofree_test_assert_no_releases_or_helper_roots(env)
}

