		is_method: true
		receiver:  autofree_test_param_at('node', 'Node', autofree_test_other_lhs_pos)
		name:      method_fn
		typ:       ast.FnType{
			params: [
				autofree_test_mut_param_at('child', 'Node', autofree_test_holder_param_pos),
				autofree_test_param_at('source', '&Node', autofree_test_source_param_pos),
			]
		}
		stmts:     [
			autofree_test_prior_local_borrowed_pointer_alias_stmt('source', 'tmp'),
			autofree_test_borrowed_pointer_field_store_stmt('child', 'tmp', 'parent'),
		]
	}
	method_flat := autofree_test_flat_with_stmts([ast.Stmt(method_decl)])
	mut method_env := Environment.new()
	autofree_test_prepare_prior_local_borrowed_pointer_field_store_env_with_types(mut method_env,
		method_fn, 'child', 'source', 'tmp', root_type, pointer_type, pointer_type, pointer_type)

