	], [ast.Stmt(nested_block)])
	autofree_test_assert_prior_local_borrowed_pointer_field_store_flat_rejected(nested_fn,
		nested_flat, 'child', 'source', 'tmp', 'parent', pointer_type)

	extra_fn := 'prior_local_borrowed_pointer_field_store_extra_statement'
	extra_flat := autofree_test_flat_with_prior_local_borrowed_pointer_field_store_stmts(extra_fn, [
