		'child', 'source', nested_rhs)
	autofree_test_assert_struct_literal_borrowed_pointer_field_initializer_flat_rejected(nested_fn,
		nested_flat, 'child', 'source', 'parent', 'Node', pointer_type)

	non_struct_fn := 'struct_literal_borrowed_pointer_field_initializer_non_struct_rhs'
