fn test_collect_autofree_direct_return_struct_literal_borrowed_pointer_field_initializer_skips_statement_and_body_shapes() {
	pointer_type := autofree_test_pointer_type('Node')
	struct_type := autofree_test_struct_literal_borrowed_pointer_holder_type('Node', 'parent',
		pointer_type)

	method_fn := 'direct_return_struct_literal_borrowed_pointer_field_initializer_method_body'
	method_decl := ast.FnDecl{
		is_method: true
		receiver:  autofree_test_param_at('holder', 'Holder', autofree_test_other_lhs_pos)
		name:      method_fn
		typ:       ast.FnType{
			params:      [
				autofree_test_param_at('source', '&Node', autofree_test_source_param_pos),
			]
			return_type: autofree_test_ident_expr('Node', autofree_test_return_type_pos)
		}
		stmts:     [
			autofree_test_direct_return_struct_literal_borrowed_pointer_field_initializer_stmt('source',
				'parent', 'Node'),
		]
	}
	method_flat := autofree_test_flat_with_stmts([ast.Stmt(method_decl)])
	autofree_test_assert_direct_return_struct_literal_borrowed_pointer_field_initializer_flat_rejected(method_fn,
		method_flat, 'source', 'parent', 'Node', pointer_type)

	nested_fn := 'direct_return_struct_literal_borrowed_pointer_field_initializer_nested_body'
	nested_block := ast.BlockStmt{
		stmts: [
			autofree_test_direct_return_struct_literal_borrowed_pointer_field_initializer_stmt('source',
				'parent', 'Node'),
		]
	}
	nested_flat := autofree_test_flat_with_direct_return_struct_literal_borrowed_pointer_field_initializer_stmts(nested_fn, [
		autofree_test_param_at('source', '&Node', autofree_test_source_param_pos),
	], 'Node', [ast.Stmt(nested_block)])
	autofree_test_assert_direct_return_struct_literal_borrowed_pointer_field_initializer_flat_rejected(nested_fn,
		nested_flat, 'source', 'parent', 'Node', pointer_type)

	extra_fn := 'direct_return_struct_literal_borrowed_pointer_field_initializer_extra_statement'
	extra_flat := autofree_test_flat_with_direct_return_struct_literal_borrowed_pointer_field_initializer_stmts(extra_fn, [
		autofree_test_param_at('source', '&Node', autofree_test_source_param_pos),
	], 'Node', [
		autofree_test_call_stmt('touch', autofree_test_ident_expr('source',
			autofree_test_third_rhs_pos), autofree_test_call_pos),
		autofree_test_direct_return_struct_literal_borrowed_pointer_field_initializer_stmt('source',
			'parent', 'Node'),
	])
	autofree_test_assert_direct_return_struct_literal_borrowed_pointer_field_initializer_flat_rejected(extra_fn,
		extra_flat, 'source', 'parent', 'Node', pointer_type)

	local_return_fn := 'direct_return_struct_literal_borrowed_pointer_field_initializer_local_return'
	local_return_flat := autofree_test_flat_with_direct_return_struct_literal_borrowed_pointer_field_initializer_stmts(local_return_fn, [
		autofree_test_param_at('source', '&Node', autofree_test_source_param_pos),
	], 'Node', [
		autofree_test_struct_literal_borrowed_pointer_field_initializer_stmt('child', 'source',
			'parent', 'Node'),
		autofree_test_return_stmt(autofree_test_ident_expr('child', autofree_test_return_pos)),
	])
	mut local_return_env := Environment.new()
	autofree_test_prepare_struct_literal_borrowed_pointer_field_initializer_env_with_types(mut local_return_env,
		local_return_fn, 'child', 'source', struct_type, pointer_type)
	local_return_env.set_expr_type(autofree_test_return_type_pos, struct_type)
	local_return_env.set_expr_type(autofree_test_return_pos, struct_type)

	local_return_env.collect_autofree_facts_from_flat(&local_return_flat)

	autofree_test_assert_no_direct_return_struct_literal_borrowed_pointer_field_initializer_or_releases(local_return_env,
		'parent')
