fn test_collect_autofree_prior_local_return_struct_literal_borrowed_pointer_field_initializer_skips_statement_and_body_shapes() {
	pointer_type := autofree_test_pointer_type('Node')

	method_fn := 'prior_local_return_struct_literal_borrowed_pointer_field_initializer_method_body'
	method_decl := ast.FnDecl{
		is_method: true
		receiver:  autofree_test_param_at('holder', 'Holder', autofree_test_other_lhs_pos)
		name:      method_fn
		typ:       ast.FnType{
			params:      [
				autofree_test_param_at('source', '&Node', autofree_test_source_param_pos),
			]
			return_type: autofree_test_ident_expr('Node', autofree_test_return_type_pos)
		}
		stmts:     [
			autofree_test_prior_local_borrowed_pointer_alias_stmt('source', 'tmp'),
			autofree_test_prior_local_return_struct_literal_borrowed_pointer_field_initializer_stmt('tmp',
				'parent', 'Node'),
		]
	}
	method_flat := autofree_test_flat_with_stmts([ast.Stmt(method_decl)])
	autofree_test_assert_prior_local_return_struct_literal_borrowed_pointer_field_initializer_flat_rejected(method_fn,
		method_flat, 'source', 'tmp', 'parent', 'Node', pointer_type)

	nested_fn := 'prior_local_return_struct_literal_borrowed_pointer_field_initializer_nested_body'
	nested_block := ast.BlockStmt{
		stmts: [
			autofree_test_prior_local_borrowed_pointer_alias_stmt('source', 'tmp'),
			autofree_test_prior_local_return_struct_literal_borrowed_pointer_field_initializer_stmt('tmp',
				'parent', 'Node'),
		]
	}
	nested_flat := autofree_test_flat_with_prior_local_return_struct_literal_borrowed_pointer_field_initializer_stmts(nested_fn, [
		autofree_test_param_at('source', '&Node', autofree_test_source_param_pos),
	], 'Node', [ast.Stmt(nested_block)])
	autofree_test_assert_prior_local_return_struct_literal_borrowed_pointer_field_initializer_flat_rejected(nested_fn,
		nested_flat, 'source', 'tmp', 'parent', 'Node', pointer_type)
}

fn test_collect_autofree_direct_sumtype_wrap_payload_fixture_uses_exact_call_or_cast_shape() {
	flat := autofree_test_flat_with_direct_sumtype_wrap_payload('sumtype_wrap_payload_shape')
	wrap_id := autofree_test_node_id_by_kind_pos(flat, .expr_call_or_cast, autofree_test_rhs_pos)
	wrap_node := flat.nodes[wrap_id]
	assert wrap_node.edge_count == 2
	callee_id := flat.edges[wrap_node.first_edge].child_id
	source_id := flat.edges[wrap_node.first_edge + 1].child_id
	assert flat.nodes[callee_id].kind == .expr_ident
	assert flat.string_at(flat.nodes[callee_id].name_id) == 'Payload'
	assert flat.nodes[callee_id].pos.id == autofree_test_rhs_pos
	assert flat.nodes[source_id].kind == .expr_ident
	assert flat.string_at(flat.nodes[source_id].name_id) == 'source'
	assert flat.nodes[source_id].pos.id == autofree_test_second_rhs_pos
	mut unsupported_shape_count := 0
	for node in flat.nodes {
		if node.pos.id == autofree_test_rhs_pos
			&& (node.kind == .expr_call || node.kind == .expr_cast || node.kind == .expr_as_cast) {
			unsupported_shape_count++
		}
	}
	assert unsupported_shape_count == 0
}

