fn test_collect_autofree_struct_literal_field_sumtype_wrap_payload_fixture_uses_nested_call_or_cast_shape() {
	flat :=
		autofree_test_flat_with_struct_literal_field_sumtype_wrap_payload('struct_literal_field_sumtype_wrap_payload_shape')
	init_id := autofree_test_node_id_by_kind_pos(flat, .expr_init, autofree_test_rhs_pos)
	wrap_id := autofree_test_node_id_by_kind_pos(flat, .expr_call_or_cast,
		autofree_test_second_rhs_pos)
	assert init_id != ast.invalid_flat_node_id
	assert wrap_id != ast.invalid_flat_node_id
	wrap_node := flat.nodes[wrap_id]
	assert wrap_node.edge_count == 2
	callee_id := flat.edges[wrap_node.first_edge].child_id
	source_id := flat.edges[wrap_node.first_edge + 1].child_id
	assert flat.nodes[callee_id].kind == .expr_ident
	assert flat.string_at(flat.nodes[callee_id].name_id) == 'Payload'
	assert flat.nodes[callee_id].pos.id == autofree_test_second_rhs_pos
	assert flat.nodes[source_id].kind == .expr_ident
	assert flat.string_at(flat.nodes[source_id].name_id) == 'source'
	assert flat.nodes[source_id].pos.id == autofree_test_third_rhs_pos
	mut unsupported_shape_count := 0
	for node in flat.nodes {
		if node.pos.id == autofree_test_second_rhs_pos
			&& (node.kind == .expr_call || node.kind == .expr_cast || node.kind == .expr_as_cast) {
			unsupported_shape_count++
		}
	}
	assert unsupported_shape_count == 0
}

