fn test_collect_autofree_struct_literal_field_sumtype_wrap_payload_skips_statement_and_body_shapes() {
	full_type := autofree_test_sumtype_wrap_full_variant_type('Full')
	assign_fn := 'struct_literal_field_sumtype_wrap_payload_non_decl_assignment'
	assign_stmt := autofree_test_assign_stmt_with_op(autofree_test_ident_expr('holder',
