	method_flat := autofree_test_flat_with_stmts([ast.Stmt(method_decl)])
	autofree_test_assert_struct_literal_field_sumtype_wrap_payload_flat_rejected(method_fn,
		method_flat, 'holder', 'source', 'payload', 'Holder', 'Payload', 'Full', full_type)

	nested_fn := 'struct_literal_field_sumtype_wrap_payload_nested_body'
