	])
	autofree_test_assert_struct_literal_field_sumtype_wrap_payload_flat_rejected(extra_fn,
		extra_flat, 'holder', 'source', 'payload', 'Holder', 'Payload', 'Full', full_type)

	return_fn := 'struct_literal_field_sumtype_wrap_payload_return_wrap'
