			'payload', 'Payload', 'source')),
	])
	autofree_test_assert_struct_literal_field_sumtype_wrap_payload_flat_rejected(return_fn,
		return_flat, 'holder', 'source', 'payload', 'Holder', 'Payload', 'Full', full_type)

