	autofree_test_assert_direct_return_struct_literal_field_sumtype_wrap_payload_flat_rejected(nested_fn,
		nested_flat, 'source', 'payload', 'Holder', 'Payload', 'Full', full_type)

	extra_fn := 'direct_return_struct_literal_field_sumtype_wrap_payload_extra_statement'
	extra_flat := autofree_test_flat_with_direct_return_struct_literal_field_sumtype_wrap_payload_stmts(extra_fn, [
		autofree_test_param_at('source', 'Full', autofree_test_source_param_pos),
	], 'Holder', [
