			'payload', 'Holder', 'Payload'),
	])
	autofree_test_assert_direct_return_struct_literal_field_sumtype_wrap_payload_flat_rejected(extra_fn,
		extra_flat, 'source', 'payload', 'Holder', 'Payload', 'Full', full_type)

	non_return_fn := 'direct_return_struct_literal_field_sumtype_wrap_payload_non_return_stmt'
	non_return_flat := autofree_test_flat_with_direct_return_struct_literal_field_sumtype_wrap_payload_stmts(non_return_fn, [
