fn test_collect_autofree_local_holder_return_interop_skips_alias_order_statement_and_body_shapes() {
	full_type := autofree_test_sumtype_wrap_full_variant_type('Full')
	payload_type := autofree_test_sumtype_wrap_payload_type('Payload', full_type)
	holder_type := autofree_test_struct_literal_field_sumtype_wrap_holder_type('Holder', 'payload',
		payload_type)

	alias_chain_fn := 'local_holder_return_interop_alias_chain'
	alias_chain_flat := autofree_test_flat_with_free_function(alias_chain_fn, [
		autofree_test_param_at('source', 'Full', autofree_test_source_param_pos),
	], [
		autofree_test_prior_local_sumtype_wrap_payload_alias_stmt_at('source', 'alias',
			autofree_test_other_lhs_pos, autofree_test_other_rhs_pos),
		autofree_test_prior_local_sumtype_wrap_payload_alias_stmt_at('alias', 'tmp',
			autofree_test_call_pos, autofree_test_field_pos),
		autofree_test_prior_local_struct_literal_field_sumtype_wrap_payload_stmt('holder', 'tmp',
			'payload', 'Holder', 'Payload'),
		autofree_test_return_stmt(autofree_test_ident_expr('holder', autofree_test_return_pos)),
	])
	mut alias_chain_env := Environment.new()
	autofree_test_prepare_prior_local_struct_literal_field_sumtype_wrap_payload_env_with_types_and_vars(mut alias_chain_env,
		alias_chain_fn, 'holder', 'source', 'tmp', holder_type, payload_type, full_type, {
		'alias': full_type
	})
	alias_chain_env.set_expr_type(autofree_test_other_lhs_pos, full_type)
	alias_chain_env.set_expr_type(autofree_test_other_rhs_pos, full_type)
	alias_chain_env.set_expr_type(autofree_test_call_pos, full_type)
	alias_chain_env.set_expr_type(autofree_test_field_pos, full_type)
	alias_chain_env.set_expr_type(autofree_test_return_type_pos, holder_type)
	alias_chain_env.set_expr_type(autofree_test_return_pos, holder_type)

	alias_chain_env.collect_autofree_facts_from_flat(&alias_chain_flat)

	autofree_test_assert_no_local_holder_return_interop_or_releases(alias_chain_env)

	wrong_order_fn := 'local_holder_return_interop_wrong_order'
	wrong_order_flat := autofree_test_flat_with_local_holder_return_interop_stmts(wrong_order_fn, [
		autofree_test_param_at('source', 'Full', autofree_test_source_param_pos),
	], 'Holder', [
		autofree_test_return_stmt(autofree_test_ident_expr('holder', autofree_test_return_pos)),
		autofree_test_struct_literal_field_sumtype_wrap_payload_stmt('holder', 'source', 'payload',
			'Holder', 'Payload'),
	])
	autofree_test_assert_local_holder_return_interop_flat_rejected(wrong_order_fn,
		wrong_order_flat, 'holder', 'source', 'payload', 'Holder', 'Payload', 'Full', full_type)

	extra_fn := 'local_holder_return_interop_extra_statement'
	extra_flat := autofree_test_flat_with_local_holder_return_interop_stmts(extra_fn, [
		autofree_test_param_at('source', 'Full', autofree_test_source_param_pos),
	], 'Holder', [
		autofree_test_struct_literal_field_sumtype_wrap_payload_stmt('holder', 'source', 'payload',
			'Holder', 'Payload'),
		autofree_test_call_stmt('touch', autofree_test_ident_expr('holder',
			autofree_test_other_rhs_pos), autofree_test_call_pos),
		autofree_test_return_stmt(autofree_test_ident_expr('holder', autofree_test_return_pos)),
	])
	autofree_test_assert_local_holder_return_interop_flat_rejected(extra_fn, extra_flat, 'holder',
		'source', 'payload', 'Holder', 'Payload', 'Full', full_type)

	method_fn := 'local_holder_return_interop_method_body'
	method_decl := ast.FnDecl{
		is_method: true
		receiver:  autofree_test_param_at('receiver', 'Receiver', autofree_test_call_pos)
		name:      method_fn
		typ:       ast.FnType{
			params:      [
				autofree_test_param_at('source', 'Full', autofree_test_source_param_pos),
			]
			return_type: autofree_test_ident_expr('Holder', autofree_test_return_type_pos)
		}
		stmts:     [
			autofree_test_struct_literal_field_sumtype_wrap_payload_stmt('holder', 'source',
				'payload', 'Holder', 'Payload'),
			autofree_test_return_stmt(autofree_test_ident_expr('holder', autofree_test_return_pos)),
		]
	}
	method_flat := autofree_test_flat_with_stmts([ast.Stmt(method_decl)])
	autofree_test_assert_local_holder_return_interop_flat_rejected(method_fn, method_flat,
