fn test_collect_autofree_prior_local_holder_return_interop_keeps_neighbor_transfer_shapes_distinct() {
	full_type := autofree_test_sumtype_wrap_full_variant_type('Full')
	payload_type := autofree_test_sumtype_wrap_payload_type('Payload', full_type)
	holder_type := autofree_test_struct_literal_field_sumtype_wrap_holder_type('Holder', 'payload',
		payload_type)

	direct_local_fn := 'prior_local_holder_return_interop_direct_local_guard'
	direct_local_flat := autofree_test_flat_with_local_holder_return_interop(direct_local_fn)
	mut direct_local_env := Environment.new()
	autofree_test_prepare_local_holder_return_interop_env_with_types(mut direct_local_env,
		direct_local_fn, 'holder', 'source', holder_type, payload_type, full_type)

	direct_local_env.collect_autofree_facts_from_flat(&direct_local_flat)

	assert direct_local_fn in direct_local_env.autofree_transfers_by_fn_key
	direct_local_transfers := direct_local_env.autofree_transfers_by_fn_key[direct_local_fn]
	assert direct_local_transfers.len == 2
	assert direct_local_transfers[0].kind == .sumtype_wrap
	assert direct_local_transfers[1].kind == .return_expr
	for transfer in direct_local_transfers {
		assert transfer.kind != .decl
	}
	autofree_test_assert_local_holder_return_interop_transfers(direct_local_env, direct_local_flat,
		direct_local_fn, holder_type, full_type, payload_type, 'holder', 'source', 'payload',
		'Holder', 'Payload', 'Full')

	prior_return_fn := 'prior_local_holder_return_interop_prior_return_guard'
	prior_return_flat :=
		autofree_test_flat_with_prior_local_return_struct_literal_field_sumtype_wrap_payload(prior_return_fn)
	mut prior_return_env := Environment.new()
	autofree_test_prepare_prior_local_return_struct_literal_field_sumtype_wrap_payload_env_with_types(mut prior_return_env,
		prior_return_fn, 'source', 'tmp', holder_type, payload_type, full_type)

	prior_return_env.collect_autofree_facts_from_flat(&prior_return_flat)

	assert prior_return_fn in prior_return_env.autofree_transfers_by_fn_key
	prior_return_transfers := prior_return_env.autofree_transfers_by_fn_key[prior_return_fn]
	assert prior_return_transfers.len == 2
	assert prior_return_transfers[0].kind == .decl
	assert prior_return_transfers[1].kind == .sumtype_wrap
	for transfer in prior_return_transfers {
		assert transfer.kind != .return_expr
	}
	autofree_test_assert_prior_local_return_struct_literal_field_sumtype_wrap_payload_transfer(prior_return_env,
		prior_return_flat, prior_return_fn, holder_type, full_type, payload_type, 'source', 'tmp',
		'payload', 'Holder', 'Payload', 'Full')

	prior_local_init_fn := 'prior_local_holder_return_interop_prior_local_init_guard'
	prior_local_init_flat :=
		autofree_test_flat_with_prior_local_struct_literal_field_sumtype_wrap_payload(prior_local_init_fn)
	mut prior_local_init_env := Environment.new()
	autofree_test_prepare_prior_local_struct_literal_field_sumtype_wrap_payload_env_with_types(mut prior_local_init_env,
		prior_local_init_fn, 'holder', 'source', 'tmp', holder_type, payload_type, full_type)

	prior_local_init_env.collect_autofree_facts_from_flat(&prior_local_init_flat)

	assert prior_local_init_fn in prior_local_init_env.autofree_transfers_by_fn_key
	prior_local_init_transfers := prior_local_init_env.autofree_transfers_by_fn_key[prior_local_init_fn]
	assert prior_local_init_transfers.len == 2
	for transfer in prior_local_init_transfers {
		assert transfer.kind != .return_expr
	}
	autofree_test_assert_prior_local_struct_literal_field_sumtype_wrap_payload_transfer(prior_local_init_env,
		prior_local_init_flat, prior_local_init_fn, holder_type, full_type, payload_type, 'holder',
		'source', 'tmp', 'payload', 'Holder', 'Payload', 'Full')

	direct_return_fn := 'prior_local_holder_return_interop_direct_return_guard'
	direct_return_flat :=
		autofree_test_flat_with_direct_return_struct_literal_field_sumtype_wrap_payload(direct_return_fn)
	mut direct_return_env := Environment.new()
	autofree_test_prepare_direct_return_struct_literal_field_sumtype_wrap_payload_env_with_types(mut direct_return_env,
		direct_return_fn, 'source', holder_type, payload_type, full_type)

	direct_return_env.collect_autofree_facts_from_flat(&direct_return_flat)

	assert direct_return_fn in direct_return_env.autofree_transfers_by_fn_key
	direct_return_transfers := direct_return_env.autofree_transfers_by_fn_key[direct_return_fn]
	assert direct_return_transfers.len == 1
	for transfer in direct_return_transfers {
		assert transfer.kind != .return_expr
	}
	autofree_test_assert_direct_return_struct_literal_field_sumtype_wrap_payload_transfer(direct_return_env,
		direct_return_flat, direct_return_fn, holder_type, full_type, payload_type, 'source',
		'payload', 'Holder', 'Payload', 'Full')
}

fn test_collect_autofree_prior_local_holder_return_interop_skips_alias_order_and_body_shapes() {
	full_type := autofree_test_sumtype_wrap_full_variant_type('Full')
	payload_type := autofree_test_sumtype_wrap_payload_type('Payload', full_type)
	holder_type := autofree_test_struct_literal_field_sumtype_wrap_holder_type('Holder', 'payload',
		payload_type)

	alias_chain_fn := 'prior_local_holder_return_interop_alias_chain'
	alias_chain_flat := autofree_test_flat_with_prior_local_holder_return_interop_stmts(alias_chain_fn, [
		autofree_test_param_at('source', 'Full', autofree_test_source_param_pos),
	], 'Holder', [
		autofree_test_prior_local_sumtype_wrap_payload_alias_stmt_at('source', 'alias',
			autofree_test_other_lhs_pos, autofree_test_call_pos),
		autofree_test_prior_local_sumtype_wrap_payload_alias_stmt_at('alias', 'tmp',
			autofree_test_lhs_pos, autofree_test_rhs_pos),
		autofree_test_prior_local_struct_literal_field_sumtype_wrap_payload_stmt('holder', 'tmp',
			'payload', 'Holder', 'Payload'),
		autofree_test_return_stmt(autofree_test_ident_expr('holder', autofree_test_return_pos)),
	])
	mut alias_chain_env := Environment.new()
	autofree_test_prepare_prior_local_holder_return_interop_env_with_types_and_vars(mut alias_chain_env,
		alias_chain_fn, 'holder', 'source', 'tmp', holder_type, payload_type, full_type, {
		'alias': full_type
	})
	alias_chain_env.set_expr_type(autofree_test_other_lhs_pos, full_type)
	alias_chain_env.set_expr_type(autofree_test_call_pos, full_type)

	alias_chain_env.collect_autofree_facts_from_flat(&alias_chain_flat)

	autofree_test_assert_no_prior_local_holder_return_interop_or_releases(alias_chain_env)

	wrong_order_fn := 'prior_local_holder_return_interop_wrong_order'
	wrong_order_flat := autofree_test_flat_with_prior_local_holder_return_interop_stmts(wrong_order_fn, [
		autofree_test_param_at('source', 'Full', autofree_test_source_param_pos),
	], 'Holder', [
		autofree_test_prior_local_struct_literal_field_sumtype_wrap_payload_stmt('holder', 'tmp',
			'payload', 'Holder', 'Payload'),
		autofree_test_prior_local_sumtype_wrap_payload_alias_stmt('source', 'tmp'),
		autofree_test_return_stmt(autofree_test_ident_expr('holder', autofree_test_return_pos)),
	])
	autofree_test_assert_prior_local_holder_return_interop_flat_rejected(wrong_order_fn,
		wrong_order_flat, 'holder', 'source', 'tmp', 'payload', 'Holder', 'Payload', 'Full',
		full_type)

	extra_fn := 'prior_local_holder_return_interop_extra_statement'
	extra_flat := autofree_test_flat_with_prior_local_holder_return_interop_stmts(extra_fn, [
		autofree_test_param_at('source', 'Full', autofree_test_source_param_pos),
	], 'Holder', [
		autofree_test_prior_local_sumtype_wrap_payload_alias_stmt('source', 'tmp'),
		autofree_test_prior_local_struct_literal_field_sumtype_wrap_payload_stmt('holder', 'tmp',
			'payload', 'Holder', 'Payload'),
		autofree_test_call_stmt('touch', autofree_test_ident_expr('holder',
			autofree_test_other_lhs_pos), autofree_test_call_pos),
		autofree_test_return_stmt(autofree_test_ident_expr('holder', autofree_test_return_pos)),
	])
	autofree_test_assert_prior_local_holder_return_interop_flat_rejected(extra_fn, extra_flat,
		'holder', 'source', 'tmp', 'payload', 'Holder', 'Payload', 'Full', full_type)

	missing_return_fn := 'prior_local_holder_return_interop_missing_return'
	missing_return_flat := autofree_test_flat_with_prior_local_holder_return_interop_stmts(missing_return_fn, [
		autofree_test_param_at('source', 'Full', autofree_test_source_param_pos),
	], 'Holder', [
		autofree_test_prior_local_sumtype_wrap_payload_alias_stmt('source', 'tmp'),
		autofree_test_prior_local_struct_literal_field_sumtype_wrap_payload_stmt('holder', 'tmp',
			'payload', 'Holder', 'Payload'),
	])
	autofree_test_assert_prior_local_holder_return_interop_flat_rejected(missing_return_fn,
		missing_return_flat, 'holder', 'source', 'tmp', 'payload', 'Holder', 'Payload', 'Full',
		full_type)

	method_fn := 'prior_local_holder_return_interop_method_body'
	method_decl := ast.FnDecl{
		is_method: true
		receiver:  autofree_test_param_at('receiver', 'Receiver', autofree_test_call_pos)
		name:      method_fn
		typ:       ast.FnType{
			params:      [
				autofree_test_param_at('source', 'Full', autofree_test_source_param_pos),
			]
			return_type: autofree_test_ident_expr('Holder', autofree_test_return_type_pos)
		}
		stmts:     [
			autofree_test_prior_local_sumtype_wrap_payload_alias_stmt('source', 'tmp'),
			autofree_test_prior_local_struct_literal_field_sumtype_wrap_payload_stmt('holder',
				'tmp', 'payload', 'Holder', 'Payload'),
			autofree_test_return_stmt(autofree_test_ident_expr('holder', autofree_test_return_pos)),
		]
	}
	method_flat := autofree_test_flat_with_stmts([ast.Stmt(method_decl)])
	autofree_test_assert_prior_local_holder_return_interop_flat_rejected(method_fn, method_flat,
		'holder', 'source', 'tmp', 'payload', 'Holder', 'Payload', 'Full', full_type)

	nested_fn := 'prior_local_holder_return_interop_nested_body'
	nested_block := ast.BlockStmt{
		stmts: [
			autofree_test_prior_local_sumtype_wrap_payload_alias_stmt('source', 'tmp'),
			autofree_test_prior_local_struct_literal_field_sumtype_wrap_payload_stmt('holder',
				'tmp', 'payload', 'Holder', 'Payload'),
			autofree_test_return_stmt(autofree_test_ident_expr('holder', autofree_test_return_pos)),
		]
	}
	nested_flat := autofree_test_flat_with_prior_local_holder_return_interop_stmts(nested_fn, [
		autofree_test_param_at('source', 'Full', autofree_test_source_param_pos),
	], 'Holder', [ast.Stmt(nested_block)])
	autofree_test_assert_prior_local_holder_return_interop_flat_rejected(nested_fn, nested_flat,
		'holder', 'source', 'tmp', 'payload', 'Holder', 'Payload', 'Full', full_type)
}

