fn test_collect_autofree_prior_local_holder_return_interop_skips_bad_struct_init_shapes() {
	full_type := autofree_test_sumtype_wrap_full_variant_type('Full')
	payload_value := autofree_test_prior_local_struct_literal_field_sumtype_wrap_payload_value('Payload',
		'tmp')

	multi_fn := 'prior_local_holder_return_interop_multi_field'
	multi_rhs := autofree_test_struct_literal_expr_at('Holder', [
		autofree_test_struct_literal_field('payload', payload_value),
		autofree_test_struct_literal_field('other', autofree_test_int_expr('0',
			autofree_test_call_pos)),
	], autofree_test_second_rhs_pos, autofree_test_struct_type_pos)
	multi_flat := autofree_test_flat_with_prior_local_holder_return_interop_rhs(multi_fn, 'holder',
		'source', 'tmp', 'Holder', multi_rhs)
	autofree_test_assert_prior_local_holder_return_interop_flat_rejected(multi_fn, multi_flat,
		'holder', 'source', 'tmp', 'payload', 'Holder', 'Payload', 'Full', full_type)

	missing_field_fn := 'prior_local_holder_return_interop_missing_field'
	missing_field_rhs := autofree_test_struct_literal_expr_at('Holder', []ast.FieldInit{},
		autofree_test_second_rhs_pos, autofree_test_struct_type_pos)
	missing_field_flat := autofree_test_flat_with_prior_local_holder_return_interop_rhs(missing_field_fn,
		'holder', 'source', 'tmp', 'Holder', missing_field_rhs)
	autofree_test_assert_prior_local_holder_return_interop_flat_rejected(missing_field_fn,
		missing_field_flat, 'holder', 'source', 'tmp', 'payload', 'Holder', 'Payload', 'Full',
		full_type)

	duplicate_field_fn := 'prior_local_holder_return_interop_duplicate_field'
	duplicate_field_rhs := autofree_test_struct_literal_expr_at('Holder', [
		autofree_test_struct_literal_field('payload', payload_value),
		autofree_test_struct_literal_field('payload', payload_value),
	], autofree_test_second_rhs_pos, autofree_test_struct_type_pos)
	duplicate_field_flat := autofree_test_flat_with_prior_local_holder_return_interop_rhs(duplicate_field_fn,
		'holder', 'source', 'tmp', 'Holder', duplicate_field_rhs)
	autofree_test_assert_prior_local_holder_return_interop_flat_rejected(duplicate_field_fn,
		duplicate_field_flat, 'holder', 'source', 'tmp', 'payload', 'Holder', 'Payload', 'Full',
		full_type)

	nested_fn := 'prior_local_holder_return_interop_nested_init'
	nested_rhs := autofree_test_prior_local_struct_literal_field_sumtype_wrap_payload_rhs_with_field_value('Holder',
		'payload', autofree_test_struct_literal_expr_at('Holder', [
		autofree_test_struct_literal_field('payload', payload_value),
	], autofree_test_second_rhs_pos, autofree_test_nested_field_pos))
	nested_flat := autofree_test_flat_with_prior_local_holder_return_interop_rhs(nested_fn,
		'holder', 'source', 'tmp', 'Holder', nested_rhs)
	autofree_test_assert_prior_local_holder_return_interop_flat_rejected(nested_fn, nested_flat,
		'holder', 'source', 'tmp', 'payload', 'Holder', 'Payload', 'Full', full_type)

	assoc_fn := 'prior_local_holder_return_interop_assoc_update'
	assoc_rhs := ast.Expr(ast.AssocExpr{
		typ:    autofree_test_ident_expr('Holder', autofree_test_struct_type_pos)
		expr:   autofree_test_ident_expr('base', autofree_test_cache_root_pos)
		fields: [
			autofree_test_struct_literal_field('payload', payload_value),
		]
		pos:    autofree_test_pos(autofree_test_second_rhs_pos)
	})
	assoc_flat := autofree_test_flat_with_prior_local_holder_return_interop_rhs(assoc_fn, 'holder',
		'source', 'tmp', 'Holder', assoc_rhs)
	autofree_test_assert_prior_local_holder_return_interop_flat_rejected(assoc_fn, assoc_flat,
		'holder', 'source', 'tmp', 'payload', 'Holder', 'Payload', 'Full', full_type)

	implicit_fn := 'prior_local_holder_return_interop_implicit_payload'
	implicit_rhs := autofree_test_prior_local_struct_literal_field_sumtype_wrap_payload_rhs_with_field_value('Holder',
		'payload', autofree_test_ident_expr('tmp', autofree_test_other_rhs_pos))
	implicit_flat := autofree_test_flat_with_prior_local_holder_return_interop_rhs(implicit_fn,
		'holder', 'source', 'tmp', 'Holder', implicit_rhs)
	autofree_test_assert_prior_local_holder_return_interop_flat_rejected(implicit_fn,
		implicit_flat, 'holder', 'source', 'tmp', 'payload', 'Holder', 'Payload', 'Full', full_type)
}

