		duplicate_variant_fn, 'holder', 'source', 'tmp', autofree_test_struct_literal_field_sumtype_wrap_holder_type('Holder',
		'payload', duplicate_payload_type), duplicate_payload_type, full_type)

	duplicate_variant_env.collect_autofree_facts_from_flat(&duplicate_variant_flat)

	autofree_test_assert_no_prior_local_holder_return_interop_or_releases(duplicate_variant_env)

