fn test_collect_autofree_prior_local_sumtype_wrap_payload_skips_alias_chain_order_and_extra() {
	full_type := autofree_test_sumtype_wrap_full_variant_type('Full')
	alias_chain_fn := 'prior_local_sumtype_wrap_payload_alias_chain'
	alias_chain_flat := autofree_test_flat_with_free_function(alias_chain_fn, [
		autofree_test_param_at('source', 'Full', autofree_test_source_param_pos),
	], [
		autofree_test_prior_local_sumtype_wrap_payload_alias_stmt_at('source', 'alias',
			autofree_test_other_lhs_pos, autofree_test_other_rhs_pos),
		autofree_test_prior_local_sumtype_wrap_payload_alias_stmt_at('alias', 'tmp',
			autofree_test_lhs_pos, autofree_test_rhs_pos),
		autofree_test_prior_local_sumtype_wrap_payload_stmt('payload', 'tmp', 'Payload'),
	])
	mut alias_chain_env := Environment.new()
	autofree_test_prepare_prior_local_sumtype_wrap_payload_env_with_types_and_vars(mut alias_chain_env,
		alias_chain_fn, 'payload', 'source', 'tmp', autofree_test_sumtype_wrap_payload_type('Payload',
		full_type), full_type, {
		'alias': full_type
	})
	alias_chain_env.set_expr_type(autofree_test_other_lhs_pos, full_type)
	alias_chain_env.set_expr_type(autofree_test_other_rhs_pos, full_type)

	alias_chain_env.collect_autofree_facts_from_flat(&alias_chain_flat)

	autofree_test_assert_no_prior_local_sumtype_wrap_payload_or_releases(alias_chain_env, 'Full')

	reversed_fn := 'prior_local_sumtype_wrap_payload_reversed_order'
	reversed_flat := autofree_test_flat_with_free_function(reversed_fn, [
		autofree_test_param_at('source', 'Full', autofree_test_source_param_pos),
	], [
		autofree_test_prior_local_sumtype_wrap_payload_stmt('payload', 'tmp', 'Payload'),
		autofree_test_prior_local_sumtype_wrap_payload_alias_stmt('source', 'tmp'),
	])
	autofree_test_assert_prior_local_sumtype_wrap_payload_flat_rejected(reversed_fn, reversed_flat,
		'payload', 'source', 'tmp', 'Payload', 'Full', full_type)

	extra_fn := 'prior_local_sumtype_wrap_payload_extra_statement'
	extra_flat := autofree_test_flat_with_free_function(extra_fn, [
		autofree_test_param_at('source', 'Full', autofree_test_source_param_pos),
	], [
		autofree_test_prior_local_sumtype_wrap_payload_alias_stmt('source', 'tmp'),
		autofree_test_prior_local_sumtype_wrap_payload_stmt('payload', 'tmp', 'Payload'),
		autofree_test_call_stmt('touch', autofree_test_ident_expr('tmp',
			autofree_test_third_rhs_pos), autofree_test_call_pos),
	])
	autofree_test_assert_prior_local_sumtype_wrap_payload_flat_rejected(extra_fn, extra_flat,
		'payload', 'source', 'tmp', 'Payload', 'Full', full_type)
}

fn test_collect_autofree_prior_local_sumtype_wrap_payload_skips_method_and_nested_body() {
	full_type := autofree_test_sumtype_wrap_full_variant_type('Full')
	method_fn := 'prior_local_sumtype_wrap_payload_method_body'
	method_decl := ast.FnDecl{
		is_method: true
		receiver:  autofree_test_param_at('holder', 'Holder', autofree_test_other_lhs_pos)
		name:      method_fn
		typ:       ast.FnType{
			params: [
				autofree_test_param_at('source', 'Full', autofree_test_source_param_pos),
			]
		}
		stmts:     [
			autofree_test_prior_local_sumtype_wrap_payload_alias_stmt('source', 'tmp'),
			autofree_test_prior_local_sumtype_wrap_payload_stmt('payload', 'tmp', 'Payload'),
		]
	}
	method_flat := autofree_test_flat_with_stmts([ast.Stmt(method_decl)])
	autofree_test_assert_prior_local_sumtype_wrap_payload_flat_rejected(method_fn, method_flat,
		'payload', 'source', 'tmp', 'Payload', 'Full', full_type)

	nested_fn := 'prior_local_sumtype_wrap_payload_nested_body'
	nested_block := ast.BlockStmt{
		stmts: [
			autofree_test_prior_local_sumtype_wrap_payload_alias_stmt('source', 'tmp'),
			autofree_test_prior_local_sumtype_wrap_payload_stmt('payload', 'tmp', 'Payload'),
		]
	}
	nested_flat := autofree_test_flat_with_free_function(nested_fn, [
		autofree_test_param_at('source', 'Full', autofree_test_source_param_pos),
	], [ast.Stmt(nested_block)])
	autofree_test_assert_prior_local_sumtype_wrap_payload_flat_rejected(nested_fn, nested_flat,
		'payload', 'source', 'tmp', 'Payload', 'Full', full_type)
}

fn test_collect_autofree_prior_local_sumtype_wrap_payload_skips_bad_tmp_source_payload_bindings() {
	full_type := autofree_test_sumtype_wrap_full_variant_type('Full')
