		autofree_test_param_at('tmp', 'Full', autofree_test_lhs_pos),
	], 'payload', 'source', 'tmp', 'Payload', 'Full')
	autofree_test_assert_prior_local_sumtype_wrap_payload_flat_rejected(tmp_param_fn,
		tmp_param_flat, 'payload', 'source', 'tmp', 'Payload', 'Full', full_type)

	tmp_global_fn := 'prior_local_sumtype_wrap_payload_tmp_global'
	tmp_global_flat := autofree_test_flat_with_prior_local_sumtype_wrap_payload(tmp_global_fn)
	mut tmp_global_env := Environment.new()
