fn test_collect_autofree_prior_local_sumtype_wrap_payload_skips_bad_variant_sets() {
	full_type := autofree_test_sumtype_wrap_full_variant_type('Full')
	empty_type := Type(Struct{
		name: 'Empty'
	})
	non_sumtype_fn := 'prior_local_sumtype_wrap_payload_non_sumtype_target'
	non_sumtype_flat := autofree_test_flat_with_prior_local_sumtype_wrap_payload(non_sumtype_fn)
	mut non_sumtype_env := Environment.new()
	autofree_test_prepare_prior_local_sumtype_wrap_payload_env_with_types(mut non_sumtype_env,
		non_sumtype_fn, 'payload', 'source', 'tmp', full_type, full_type)

	non_sumtype_env.collect_autofree_facts_from_flat(&non_sumtype_flat)

	autofree_test_assert_no_prior_local_sumtype_wrap_payload_or_releases(non_sumtype_env, 'Full')

	missing_variant_fn := 'prior_local_sumtype_wrap_payload_missing_variant'
	missing_variant_flat :=
		autofree_test_flat_with_prior_local_sumtype_wrap_payload(missing_variant_fn)
	missing_variant_sumtype := autofree_test_sumtype_wrap_payload_type('Payload', empty_type)
	mut missing_variant_env := Environment.new()
	autofree_test_prepare_prior_local_sumtype_wrap_payload_env_with_types(mut missing_variant_env,
		missing_variant_fn, 'payload', 'source', 'tmp', missing_variant_sumtype, full_type)

	missing_variant_env.collect_autofree_facts_from_flat(&missing_variant_flat)

	autofree_test_assert_no_prior_local_sumtype_wrap_payload_or_releases(missing_variant_env,
		'Full')

	duplicate_fn := 'prior_local_sumtype_wrap_payload_duplicate_variant'
	duplicate_flat := autofree_test_flat_with_prior_local_sumtype_wrap_payload(duplicate_fn)
	duplicate_sumtype := Type(SumType{
		name:     'Payload'
		variants: [full_type, full_type]
	})
	mut duplicate_env := Environment.new()
	autofree_test_prepare_prior_local_sumtype_wrap_payload_env_with_types(mut duplicate_env,
		duplicate_fn, 'payload', 'source', 'tmp', duplicate_sumtype, full_type)

	duplicate_env.collect_autofree_facts_from_flat(&duplicate_flat)

	autofree_test_assert_no_prior_local_sumtype_wrap_payload_or_releases(duplicate_env, 'Full')

	scalar_fn := 'prior_local_sumtype_wrap_payload_scalar_variant'
	scalar_flat := autofree_test_flat_with_prior_local_sumtype_wrap_payload_named(scalar_fn,
		'payload', 'source', 'tmp', 'Payload', 'int')
	scalar_sumtype := autofree_test_sumtype_wrap_payload_type('Payload', Type(int_))
	mut scalar_env := Environment.new()
	autofree_test_prepare_prior_local_sumtype_wrap_payload_env_with_types(mut scalar_env,
		scalar_fn, 'payload', 'source', 'tmp', scalar_sumtype, Type(int_))

	scalar_env.collect_autofree_facts_from_flat(&scalar_flat)

	autofree_test_assert_no_prior_local_sumtype_wrap_payload_or_releases(scalar_env, 'int')

	nested_fn := 'prior_local_sumtype_wrap_payload_nested_variant'
	nested_type := autofree_test_sumtype_wrap_payload_type('NestedPayload', full_type)
	nested_flat := autofree_test_flat_with_prior_local_sumtype_wrap_payload_named(nested_fn,
		'payload', 'source', 'tmp', 'Payload', 'NestedPayload')
	nested_sumtype := autofree_test_sumtype_wrap_payload_type('Payload', nested_type)
	mut nested_env := Environment.new()
	autofree_test_prepare_prior_local_sumtype_wrap_payload_env_with_types(mut nested_env,
		nested_fn, 'payload', 'source', 'tmp', nested_sumtype, nested_type)

	nested_env.collect_autofree_facts_from_flat(&nested_flat)

	autofree_test_assert_no_prior_local_sumtype_wrap_payload_or_releases(nested_env,
		'NestedPayload')

	unsupported_fn := 'prior_local_sumtype_wrap_payload_unsupported_variant'
	unsupported_flat := autofree_test_flat_with_prior_local_sumtype_wrap_payload_named(unsupported_fn,
		'payload', 'source', 'tmp', 'Payload', 'FullAlias')
	unsupported_type := Type(NamedType('FullAlias'))
	unsupported_sumtype := autofree_test_sumtype_wrap_payload_type('Payload', unsupported_type)
	mut unsupported_env := Environment.new()
	autofree_test_prepare_prior_local_sumtype_wrap_payload_env_with_types(mut unsupported_env,
		unsupported_fn, 'payload', 'source', 'tmp', unsupported_sumtype, unsupported_type)

	unsupported_env.collect_autofree_facts_from_flat(&unsupported_flat)

	autofree_test_assert_no_prior_local_sumtype_wrap_payload_or_releases(unsupported_env,
		'FullAlias')
}

