	autofree_test_assert_prior_local_sumtype_wrap_payload_missing_type_rejected('prior_local_sumtype_wrap_payload_missing_alias_lhs_type',
		false, true, true, true, true, true, true, true, true)
	autofree_test_assert_prior_local_sumtype_wrap_payload_missing_type_rejected('prior_local_sumtype_wrap_payload_missing_alias_rhs_type',
		true, false, true, true, true, true, true, true, true)
	autofree_test_assert_prior_local_sumtype_wrap_payload_missing_type_rejected('prior_local_sumtype_wrap_payload_missing_payload_lhs_type',
		true, true, false, true, true, true, true, true, true)
	autofree_test_assert_prior_local_sumtype_wrap_payload_missing_type_rejected('prior_local_sumtype_wrap_payload_missing_wrap_type',
		true, true, true, false, true, true, true, true, true)
	autofree_test_assert_prior_local_sumtype_wrap_payload_missing_type_rejected('prior_local_sumtype_wrap_payload_missing_tmp_expr_type',
		true, true, true, true, false, true, true, true, true)
	autofree_test_assert_prior_local_sumtype_wrap_payload_missing_type_rejected('prior_local_sumtype_wrap_payload_missing_source_binding',
		true, true, true, true, true, false, true, true, true)
	autofree_test_assert_prior_local_sumtype_wrap_payload_missing_type_rejected('prior_local_sumtype_wrap_payload_missing_tmp_binding',
		true, true, true, true, true, true, false, true, true)
	autofree_test_assert_prior_local_sumtype_wrap_payload_missing_type_rejected('prior_local_sumtype_wrap_payload_missing_payload_binding',
		true, true, true, true, true, true, true, false, true)
	autofree_test_assert_prior_local_sumtype_wrap_payload_missing_type_rejected('prior_local_sumtype_wrap_payload_missing_variant_type',
		true, true, true, true, true, true, true, true, false)

	full_type := autofree_test_sumtype_wrap_full_variant_type('Full')
	other_type := autofree_test_sumtype_wrap_full_variant_type('OtherFull')
	payload_type := autofree_test_sumtype_wrap_payload_type('Payload', full_type)
	other_payload_type := autofree_test_sumtype_wrap_payload_type('Payload', other_type)
	source_mismatch_fn := 'prior_local_sumtype_wrap_payload_source_type_mismatch'
