	source_mismatch_env.collect_autofree_facts_from_flat(&source_mismatch_flat)

	autofree_test_assert_no_prior_local_sumtype_wrap_payload_or_releases(source_mismatch_env,
		'Full')

	tmp_mismatch_fn := 'prior_local_sumtype_wrap_payload_tmp_type_mismatch'
	tmp_mismatch_flat := autofree_test_flat_with_prior_local_sumtype_wrap_payload(tmp_mismatch_fn)
	mut tmp_mismatch_env := Environment.new()
	autofree_test_prepare_prior_local_sumtype_wrap_payload_env_with_types(mut tmp_mismatch_env,
		tmp_mismatch_fn, 'payload', 'source', 'tmp', payload_type, full_type)
	tmp_mismatch_env.set_expr_type(autofree_test_third_rhs_pos, other_type)

	tmp_mismatch_env.collect_autofree_facts_from_flat(&tmp_mismatch_flat)

	autofree_test_assert_no_prior_local_sumtype_wrap_payload_or_releases(tmp_mismatch_env, 'Full')

	wrap_mismatch_fn := 'prior_local_sumtype_wrap_payload_wrap_type_mismatch'
