	mut vars := map[string]Type{}
	vars[source_name] = pointer_type
	vars[cursor_name] = pointer_type
	autofree_test_add_scope_with_var_types(mut env, fn_name, vars)
	autofree_test_set_borrowed_pointer_loop_cursor_expr_types(mut env, pointer_type, pointer_type,
		pointer_type)
}

fn autofree_test_set_borrowed_pointer_loop_cursor_expr_types(mut env Environment, source_type Type, cursor_type Type, post_type Type) {
	env.set_expr_type(autofree_test_rhs_pos, source_type)
	env.set_expr_type(autofree_test_lhs_pos, cursor_type)
	env.set_expr_type(autofree_test_loop_cond_pos, Type(bool_))
	env.set_expr_type(autofree_test_post_lhs_pos, cursor_type)
	env.set_expr_type(autofree_test_post_root_pos, cursor_type)
	env.set_expr_type(autofree_test_post_rhs_pos, post_type)
}

