fn autofree_test_assert_borrowed_pointer_field_read_rhs_rejected(fn_name string, rhs ast.Expr, extra_vars map[string]Type) {
	pointer_type := autofree_test_pointer_type('Node')
	flat := autofree_test_flat_with_free_function(fn_name, [
		autofree_test_param_at('holder', 'Holder', autofree_test_holder_param_pos),
	], [autofree_test_borrowed_pointer_field_read_stmt_with_rhs('cursor', rhs)])
	root_type := autofree_test_borrowed_pointer_holder_type('parent', pointer_type)
	mut env := Environment.new()
	mut vars := map[string]Type{}
	vars['holder'] = root_type
	vars['cursor'] = pointer_type
	for name, typ in extra_vars {
		vars[name] = typ
	}
	autofree_test_add_scope_with_var_types(mut env, fn_name, vars)
	autofree_test_set_borrowed_pointer_field_read_expr_types(mut env, pointer_type, root_type,
		pointer_type)

	env.collect_autofree_facts_from_flat(&flat)

	autofree_test_assert_no_borrowed_pointer_field_read_or_releases(env, 'cursor')
}

