fn autofree_test_assert_struct_literal_borrowed_pointer_field_initializer_missing_type_rejected(fn_name string, has_lhs_type bool, has_struct_type bool, has_source_type bool, has_field_type bool) {
	pointer_type := autofree_test_pointer_type('Node')
	struct_type := if has_field_type {
		autofree_test_struct_literal_borrowed_pointer_holder_type('Node', 'parent', pointer_type)
	} else {
		autofree_test_struct_literal_borrowed_pointer_holder_type_without_field('Node')
	}
	flat := autofree_test_flat_with_struct_literal_borrowed_pointer_field_initializer(fn_name)
	mut env := Environment.new()
	mut vars := map[string]Type{}
	vars['child'] = struct_type
	vars['source'] = pointer_type
	autofree_test_add_scope_with_var_types(mut env, fn_name, vars)
	if has_lhs_type {
		env.set_expr_type(autofree_test_lhs_pos, struct_type)
	}
	if has_struct_type {
		env.set_expr_type(autofree_test_rhs_pos, struct_type)
		env.set_expr_type(autofree_test_struct_type_pos, struct_type)
	}
	if has_source_type {
		env.set_expr_type(autofree_test_source_param_pos, pointer_type)
		env.set_expr_type(autofree_test_second_rhs_pos, pointer_type)
	}

	env.collect_autofree_facts_from_flat(&flat)

	autofree_test_assert_no_struct_literal_borrowed_pointer_field_initializer_or_releases(env,
		'parent')
}

