	if 'holder' in extra_vars {
		holder_type := extra_vars['holder'] or { struct_type }
		env.set_expr_type(autofree_test_cache_root_pos, holder_type)
		env.set_expr_type(autofree_test_nested_field_pos, pointer_type)
