	} else {
		autofree_test_struct_literal_borrowed_pointer_holder_type_without_field('Node')
	}
	flat := if has_return_type {
		autofree_test_flat_with_prior_local_return_struct_literal_borrowed_pointer_field_initializer(fn_name)
	} else {
		autofree_test_flat_with_prior_local_return_struct_literal_borrowed_pointer_field_initializer_without_return_type(fn_name)
	}
	mut env := Environment.new()
	mut vars := map[string]Type{}
	if has_source_scope_type {
		vars['source'] = pointer_type
	}
	if has_tmp_scope_type {
		vars['tmp'] = pointer_type
	}
	autofree_test_add_scope_with_var_types(mut env, fn_name, vars)
	if has_return_type {
		env.set_expr_type(autofree_test_return_type_pos, struct_type)
	}
	if has_alias_lhs_type {
		env.set_expr_type(autofree_test_lhs_pos, pointer_type)
	}
	if has_source_expr_type {
		env.set_expr_type(autofree_test_rhs_pos, pointer_type)
	}
	if has_init_type {
		env.set_expr_type(autofree_test_second_rhs_pos, struct_type)
	}
	if has_struct_target_type {
		env.set_expr_type(autofree_test_struct_type_pos, struct_type)
	}
	if has_tmp_expr_type {
		env.set_expr_type(autofree_test_other_rhs_pos, pointer_type)
	}

	env.collect_autofree_facts_from_flat(&flat)

	autofree_test_assert_no_prior_local_return_struct_literal_borrowed_pointer_field_initializer_or_releases(env,
		'parent')
}

