fn autofree_test_assert_local_holder_return_interop_value_rejected(fn_name string, value ast.Expr, extra_vars map[string]Type) {
	full_type := autofree_test_sumtype_wrap_full_variant_type('Full')
	payload_type := autofree_test_sumtype_wrap_payload_type('Payload', full_type)
	holder_type := autofree_test_struct_literal_field_sumtype_wrap_holder_type('Holder', 'payload',
		payload_type)
	rhs := autofree_test_struct_literal_field_sumtype_wrap_payload_rhs_with_field_value('Holder',
		'payload', autofree_test_struct_literal_field_sumtype_wrap_payload_value_with_expr('Payload',
		value))
	flat := autofree_test_flat_with_local_holder_return_interop_rhs(fn_name, 'holder', 'source',
		'Holder', rhs)
	mut env := Environment.new()
	autofree_test_prepare_local_holder_return_interop_env_with_types_and_vars(mut env, fn_name,
		'holder', 'source', holder_type, payload_type, full_type, extra_vars)
	env.set_expr_type(autofree_test_other_rhs_pos, full_type)
	env.set_expr_type(autofree_test_index_pos, Type(int_))
	env.set_expr_type(autofree_test_key_pos, Type(int_))
	if 'carrier' in extra_vars {
		carrier_type := extra_vars['carrier'] or { full_type }
		env.set_expr_type(autofree_test_cache_root_pos, carrier_type)
		env.set_expr_type(autofree_test_nested_field_pos, full_type)
	}
	if 'items' in extra_vars {
		items_type := extra_vars['items'] or { full_type }
		env.set_expr_type(autofree_test_cache_root_pos, items_type)
	}
	if 'cache' in extra_vars {
		cache_type := extra_vars['cache'] or { full_type }
		env.set_expr_type(autofree_test_cache_root_pos, cache_type)
	}

	env.collect_autofree_facts_from_flat(&flat)

	autofree_test_assert_no_local_holder_return_interop_or_releases(env)
}

fn autofree_test_assert_local_holder_return_interop_return_expr_rejected(fn_name string, return_expr ast.Expr, extra_vars map[string]Type, return_expr_type Type) {
	full_type := autofree_test_sumtype_wrap_full_variant_type('Full')
	payload_type := autofree_test_sumtype_wrap_payload_type('Payload', full_type)
	holder_type := autofree_test_struct_literal_field_sumtype_wrap_holder_type('Holder', 'payload',
		payload_type)
	flat := autofree_test_flat_with_local_holder_return_interop_return_expr(fn_name, return_expr)
	mut env := Environment.new()
	autofree_test_prepare_local_holder_return_interop_env_with_types_and_vars(mut env, fn_name,
		'holder', 'source', holder_type, payload_type, full_type, extra_vars)
	env.set_expr_type(autofree_test_return_pos, return_expr_type)
	env.set_expr_type(autofree_test_cache_root_pos, return_expr_type)
	env.set_expr_type(autofree_test_field_pos, payload_type)
	env.set_expr_type(autofree_test_index_pos, Type(int_))
	env.set_expr_type(autofree_test_other_rhs_pos, holder_type)
	if 'other' in extra_vars {
		other_type := extra_vars['other'] or { holder_type }
		env.set_expr_type(autofree_test_return_pos, other_type)
	}
	if 'holder' in extra_vars {
		holder_scope_type := extra_vars['holder'] or { holder_type }
		env.set_expr_type(autofree_test_cache_root_pos, holder_scope_type)
	}
	if 'items' in extra_vars {
		items_type := extra_vars['items'] or { Type(Array{
			elem_type: holder_type
		}) }
		env.set_expr_type(autofree_test_cache_root_pos, items_type)
	}

	env.collect_autofree_facts_from_flat(&flat)

	autofree_test_assert_no_local_holder_return_interop_or_releases(env)
}

fn autofree_test_assert_local_holder_return_interop_missing_type_rejected(fn_name string, has_return_type bool, has_holder_lhs_type bool, has_holder_scope_type bool, has_init_type bool, has_field_type bool, has_wrap_type bool, has_source_expr_type bool, has_source_scope_type bool, has_return_expr_type bool, has_variant_type bool) {
	full_type := autofree_test_sumtype_wrap_full_variant_type('Full')
	payload_type := if has_variant_type {
		autofree_test_sumtype_wrap_payload_type('Payload', full_type)
	} else {
		Type(SumType{
			name: 'Payload'
		})
	}
	holder_type := if has_field_type {
		autofree_test_struct_literal_field_sumtype_wrap_holder_type('Holder', 'payload',
			payload_type)
	} else {
		autofree_test_struct_literal_field_sumtype_wrap_holder_type_without_field('Holder')
	}
	flat := if has_return_type {
		autofree_test_flat_with_local_holder_return_interop(fn_name)
	} else {
		autofree_test_flat_with_local_holder_return_interop_without_return_type(fn_name)
	}
	mut env := Environment.new()
	mut vars := map[string]Type{}
	if has_holder_scope_type {
		vars['holder'] = holder_type
	}
	if has_source_scope_type {
		vars['source'] = full_type
	}
	autofree_test_add_scope_with_var_types(mut env, fn_name, vars)
	if has_return_type {
		env.set_expr_type(autofree_test_return_type_pos, holder_type)
	}
	if has_holder_lhs_type {
		env.set_expr_type(autofree_test_lhs_pos, holder_type)
	}
	if has_init_type {
		env.set_expr_type(autofree_test_rhs_pos, holder_type)
	}
	if has_wrap_type {
		env.set_expr_type(autofree_test_second_rhs_pos, payload_type)
	}
	if has_source_expr_type {
		env.set_expr_type(autofree_test_source_param_pos, full_type)
		env.set_expr_type(autofree_test_third_rhs_pos, full_type)
	}
	if has_return_expr_type {
		env.set_expr_type(autofree_test_return_pos, holder_type)
	}

	env.collect_autofree_facts_from_flat(&flat)

	autofree_test_assert_no_local_holder_return_interop_or_releases(env)
}

fn autofree_test_assert_local_holder_return_interop_flat_rejected(fn_name string, flat ast.FlatAst, local_name string, source_name string, field_name string, holder_type_name string, sumtype_name string, variant_name string, source_type Type) {
	_ = variant_name
	payload_type := autofree_test_sumtype_wrap_payload_type(sumtype_name, source_type)
