		fn_name, 'holder', 'source', 'tmp', holder_type, payload_type, full_type, extra_vars)
	env.set_expr_type(autofree_test_return_pos, return_expr_type)
	env.set_expr_type(autofree_test_cache_root_pos, return_expr_type)
	env.set_expr_type(autofree_test_field_pos, payload_type)
	env.set_expr_type(autofree_test_index_pos, Type(int_))
	if 'holder' in extra_vars {
		holder_scope_type := extra_vars['holder'] or { holder_type }
		env.set_expr_type(autofree_test_cache_root_pos, holder_scope_type)
	}
	if 'items' in extra_vars {
		items_type := extra_vars['items'] or { Type(Array{
			elem_type: holder_type
		}) }
		env.set_expr_type(autofree_test_cache_root_pos, items_type)
	}

	env.collect_autofree_facts_from_flat(&flat)

	autofree_test_assert_no_prior_local_holder_return_interop_or_releases(env)
}

fn autofree_test_assert_prior_local_holder_return_interop_missing_type_rejected(fn_name string, has_return_type bool, has_alias_lhs_type bool, has_alias_rhs_type bool, has_holder_lhs_type bool, has_holder_scope_type bool, has_init_type bool, has_field_type bool, has_wrap_type bool, has_alias_expr_type bool, has_source_scope_type bool, has_alias_scope_type bool, has_return_expr_type bool, has_variant_type bool) {
	full_type := autofree_test_sumtype_wrap_full_variant_type('Full')
	payload_type := if has_variant_type {
		autofree_test_sumtype_wrap_payload_type('Payload', full_type)
	} else {
		Type(SumType{
			name: 'Payload'
		})
	}
	holder_type := if has_field_type {
		autofree_test_struct_literal_field_sumtype_wrap_holder_type('Holder', 'payload',
			payload_type)
	} else {
		autofree_test_struct_literal_field_sumtype_wrap_holder_type_without_field('Holder')
	}
	flat := if has_return_type {
		autofree_test_flat_with_prior_local_holder_return_interop(fn_name)
	} else {
		autofree_test_flat_with_prior_local_holder_return_interop_without_return_type(fn_name)
	}
	mut env := Environment.new()
	mut vars := map[string]Type{}
	if has_holder_scope_type {
		vars['holder'] = holder_type
	}
	if has_source_scope_type {
		vars['source'] = full_type
	}
	if has_alias_scope_type {
		vars['tmp'] = full_type
	}
	autofree_test_add_scope_with_var_types(mut env, fn_name, vars)
	if has_return_type {
		env.set_expr_type(autofree_test_return_type_pos, holder_type)
	}
	if has_alias_lhs_type {
		env.set_expr_type(autofree_test_lhs_pos, full_type)
	}
	if has_alias_rhs_type {
		env.set_expr_type(autofree_test_source_param_pos, full_type)
		env.set_expr_type(autofree_test_rhs_pos, full_type)
	}
	if has_holder_lhs_type {
		env.set_expr_type(autofree_test_second_lhs_pos, holder_type)
	}
	if has_init_type {
		env.set_expr_type(autofree_test_second_rhs_pos, holder_type)
		env.set_expr_type(autofree_test_struct_type_pos, holder_type)
	}
	if has_wrap_type {
		env.set_expr_type(autofree_test_third_rhs_pos, payload_type)
	}
	if has_alias_expr_type {
		env.set_expr_type(autofree_test_other_rhs_pos, full_type)
	}
	if has_return_expr_type {
		env.set_expr_type(autofree_test_return_pos, holder_type)
	}

	env.collect_autofree_facts_from_flat(&flat)

	autofree_test_assert_no_prior_local_holder_return_interop_or_releases(env)
}

