fn autofree_test_malformed_flat_with_decl_transfer() ast.FlatAst {
	mut flat := autofree_test_flat_with_direct_ident_decl_transfer()
	body_id := autofree_test_body_list_id(flat)
	if body_id >= 0 && body_id < flat.nodes.len {
		flat.nodes[body_id].edge_count = flat.edges.len + 1
	}
	return flat
}

