fn autofree_test_add_scope_with_global_and_vars(mut env Environment, fn_name string, global_name string, global_type Type, vars map[string]Type) {
	mut module_scope := new_scope(unsafe { nil })
	module_scope.insert(global_name, Global{
		name:      global_name
		mod:       'main'
		is_public: true
		is_mut:    true
		typ:       global_type
	})
	mut fn_scope := new_scope(module_scope)
	for name, typ in vars {
		fn_scope.insert(name, object_from_type(typ))
	}
	env.set_fn_scope('main', fn_name, fn_scope)
}

