fn autofree_test_node_id_by_kind_name_pos(flat ast.FlatAst, kind ast.FlatNodeKind, name string, pos_id int) ast.FlatNodeId {
	for i, node in flat.nodes {
		if node.kind == kind && flat.string_at(node.name_id) == name && node.pos.id == pos_id {
			return ast.FlatNodeId(i)
		}
	}
	assert false
	return ast.invalid_flat_node_id
}

fn autofree_test_node_id_by_kind_pos(flat ast.FlatAst, kind ast.FlatNodeKind, pos_id int) ast.FlatNodeId {
	for i, node in flat.nodes {
		if node.kind == kind && node.pos.id == pos_id {
			return ast.FlatNodeId(i)
		}
	}
	assert false
	return ast.invalid_flat_node_id
}

fn autofree_test_node_id_by_kinds_pos(flat ast.FlatAst, kinds []ast.FlatNodeKind, pos_id int) ast.FlatNodeId {
	for i, node in flat.nodes {
		if node.pos.id != pos_id {
			continue
		}
		for kind in kinds {
			if node.kind == kind {
				return ast.FlatNodeId(i)
			}
		}
	}
	assert false
	return ast.invalid_flat_node_id
}

fn autofree_test_replace_array_init_type_edge_with_ident(mut flat ast.FlatAst) {
	rhs_id := autofree_test_node_id_by_kind_pos(flat, .expr_array_init, autofree_test_rhs_pos)
	lhs_id := autofree_test_node_id_by_kind_name_pos(flat, .expr_ident, 'items',
		autofree_test_lhs_pos)
	if rhs_id < 0 || rhs_id >= flat.nodes.len {
		return
	}
	rhs_node := flat.nodes[rhs_id]
	if rhs_node.first_edge < 0 || rhs_node.first_edge >= flat.edges.len {
		return
	}
	flat.edges[rhs_node.first_edge] = ast.FlatEdge{
		child_id: lhs_id
	}
}

fn autofree_test_set_lhs_modifier_edge_count(mut flat ast.FlatAst, edge_count int) {
	modifier_id := autofree_test_node_id_by_kind_pos(flat, .expr_modifier, autofree_test_lhs_pos)
	if modifier_id < 0 || modifier_id >= flat.nodes.len {
		return
	}
	flat.nodes[modifier_id].edge_count = edge_count
}

fn autofree_test_body_list_id(flat ast.FlatAst) ast.FlatNodeId {
	if flat.files.len == 0 {
		return ast.invalid_flat_node_id
	}
	file_id := flat.files[0].file_id
	if file_id < 0 || file_id >= flat.nodes.len {
		return ast.invalid_flat_node_id
	}
	file_node := flat.nodes[file_id]
	if file_node.edge_count <= 2 || file_node.first_edge < 0 {
		return ast.invalid_flat_node_id
	}
	stmts_id := flat.edges[file_node.first_edge + 2].child_id
	if stmts_id < 0 || stmts_id >= flat.nodes.len {
		return ast.invalid_flat_node_id
	}
	stmts_node := flat.nodes[stmts_id]
	if stmts_node.edge_count == 0 || stmts_node.first_edge < 0 {
		return ast.invalid_flat_node_id
	}
	fn_id := flat.edges[stmts_node.first_edge].child_id
	if fn_id < 0 || fn_id >= flat.nodes.len {
		return ast.invalid_flat_node_id
	}
	fn_node := flat.nodes[fn_id]
	if fn_node.edge_count <= 3 || fn_node.first_edge < 0 {
		return ast.invalid_flat_node_id
	}
	return flat.edges[fn_node.first_edge + 3].child_id
}

