fn autofree_test_assert_synthetic_external_move_not_release_eligible(storage AutofreeStorageKind, root_storage AutofreeStorageKind, kind AutofreeTransferKind, name string) {
	array_type := autofree_test_move_proof_array_type()
	shape := autofree_test_move_proof_array_shape()
	transfer := autofree_test_synthetic_transfer('synthetic_external_move', name, kind, .move, autofree_test_synthetic_transfer_endpoint('external_root',
		name, storage, root_storage, array_type, shape, .owned_unique, 'synthetic external target'))
	env := autofree_test_collect_release_eligibility_for_synthetic_transfers('synthetic_external_move', [
		transfer,
	])

	assert 'synthetic_external_move' in env.autofree_release_eligibility_by_fn_key
	facts := env.autofree_release_eligibility_by_fn_key['synthetic_external_move']
	assert facts.len == 1
	fact := facts[0]
	assert fact.name == name
	assert fact.transfer_kind == kind
	assert fact.transfer_action == .move
	assert fact.endpoint.storage == storage
	assert fact.endpoint.root_storage == root_storage
	assert fact.endpoint.state == .owned_unique
	assert fact.endpoint.shape.needs_autofree()
	assert fact.eligibility == .not_release_eligible
	autofree_test_assert_no_releases_or_helper_roots(env)
}

fn autofree_test_synthetic_transfer(fn_key string, name string, kind AutofreeTransferKind, action AutofreeTransferAction, target AutofreeTransferEndpoint) AutofreeTransferFact {
	source := autofree_test_synthetic_transfer_endpoint('source', 'source', .parameter, .parameter,
		target.typ, target.shape, target.state, 'synthetic source')
	return AutofreeTransferFact{
		fn_key:        fn_key
		fn_name:       fn_key
		kind:          kind
		action:        action
		from_endpoint: source
		to_endpoint:   target
		from_name:     'source'
		to_name:       name
		typ:           target.typ
		type_name:     target.type_name
		shape:         target.shape
		node_id:       target.node_id
		pos_id:        target.pos_id
		reason:        'synthetic transfer'
	}
}

fn autofree_test_synthetic_transfer_endpoint(root_name string, name string, storage AutofreeStorageKind, root_storage AutofreeStorageKind, typ Type, shape AutofreeResourceShape, state AutofreeOwnershipState, reason string) AutofreeTransferEndpoint {
	return AutofreeTransferEndpoint{
		storage:      storage
		root_storage: root_storage
		root_name:    root_name
		name:         name
		root_node_id: ast.FlatNodeId(1)
		root_pos_id:  10
		node_id:      ast.FlatNodeId(2)
		pos_id:       20
		has_type:     true
		typ:          typ
		type_name:    typ.name()
		resource:     autofree_collect_resource_kind_from_shape(shape)
		shape:        shape
		state:        state
		reason:       reason
	}
}

