	assert transfer.to_endpoint.root_pos_id == autofree_test_holder_root_pos
	assert transfer.to_endpoint.node_id == push_id
	assert transfer.to_endpoint.pos_id == 202
	assert transfer.to_endpoint.path.len == 2
	assert transfer.to_endpoint.path[0].storage == .struct_field
	assert transfer.to_endpoint.path[0].name == 'slots'
	assert transfer.to_endpoint.path[0].node_id == field_id
	assert transfer.to_endpoint.path[0].pos_id == autofree_test_field_pos
	assert transfer.to_endpoint.path[1].storage == .array_element
	assert transfer.to_endpoint.path[1].name == '[]'
	assert transfer.to_endpoint.path[1].node_id == push_id
	assert transfer.to_endpoint.path[1].pos_id == 202
	assert transfer.to_endpoint.path[1].index_node_id == ast.invalid_flat_node_id
	assert transfer.to_endpoint.path[1].index_pos_id == 0
	assert transfer.shape.kind == .array
	assert transfer.shape.target_kind == expected_target_kind
	assert same_type_name(transfer.typ, expected_type)
	assert fn_key in env.autofree_release_eligibility_by_fn_key
	eligibility_facts := env.autofree_release_eligibility_by_fn_key[fn_key]
	alias_eligibility := autofree_test_release_eligibility_by_name(eligibility_facts, 'tmp')
	assert alias_eligibility.eligibility == .not_release_eligible
	assert alias_eligibility.transfer_kind == .decl
	assert alias_eligibility.transfer_action == .ambiguous_no_free
	assert alias_eligibility.transfer_action != .move
	assert alias_eligibility.transfer_action != .clone_value
	eligibility := autofree_test_release_eligibility_by_name(eligibility_facts, expected_name)
	assert eligibility.eligibility == .not_release_eligible
	assert eligibility.transfer_kind == .array_push
	assert eligibility.transfer_action == .ambiguous_no_free
	assert eligibility.transfer_action != .move
	assert eligibility.transfer_action != .clone_value
	assert eligibility.endpoint.storage == .array_element
	assert eligibility.endpoint.root_storage == .parameter
	assert eligibility.endpoint.root_name == 'holder'
	assert eligibility.endpoint.name == expected_name
	assert eligibility.endpoint.path.len == 2
	assert eligibility.endpoint.path[0].storage == .struct_field
	assert eligibility.endpoint.path[0].name == 'slots'
	assert eligibility.endpoint.path[0].node_id == field_id
	assert eligibility.endpoint.path[0].pos_id == autofree_test_field_pos
	assert eligibility.endpoint.path[1].storage == .array_element
	assert eligibility.endpoint.path[1].name == '[]'
	assert eligibility.endpoint.path[1].node_id == push_id
	assert eligibility.endpoint.path[1].pos_id == 202
	assert eligibility.endpoint.path[1].index_node_id == ast.invalid_flat_node_id
	assert eligibility.endpoint.path[1].index_pos_id == 0
	assert eligibility.endpoint.shape.kind == .array
	assert eligibility.endpoint.shape.target_kind == expected_target_kind
	assert same_type_name(eligibility.typ, expected_type)
	assert same_type_name(eligibility.endpoint.typ, expected_type)
	for fact in eligibility_facts {
		assert fact.eligibility != .release_eligible
		assert fact.transfer_action != .move
		assert fact.transfer_action != .clone_value
	}
	autofree_test_assert_no_releases_or_helper_roots(env)
}

