fn autofree_test_assert_no_array_element_store_or_releases(env Environment, fn_key string) {
	assert fn_key.len > 0
	for _, transfers in env.autofree_transfers_by_fn_key {
		for transfer in transfers {
			if transfer.kind == .assign {
				assert transfer.to_endpoint.storage != .array_element
			}
			assert transfer.action != .move
			assert transfer.action != .clone_value
		}
	}
	for _, facts in env.autofree_release_eligibility_by_fn_key {
		for fact in facts {
			assert fact.eligibility != .release_eligible
			if fact.transfer_kind == .assign {
				assert fact.endpoint.storage != .array_element
			}
			assert fact.transfer_action != .move
			assert fact.transfer_action != .clone_value
		}
	}
	autofree_test_assert_no_releases_or_helper_roots(env)
}

fn autofree_test_assert_no_array_push_or_releases(env Environment, fn_key string) {
	assert fn_key.len > 0
	for _, transfers in env.autofree_transfers_by_fn_key {
		for transfer in transfers {
			assert transfer.kind != .array_push
			assert transfer.action != .move
			assert transfer.action != .clone_value
			assert transfer.to_name != 'slots[]'
		}
