			assert fact.transfer_action != .clone_value
			assert fact.name != 'slots[]'
			assert fact.endpoint.name != 'slots[]'
		}
	}
	autofree_test_assert_no_releases_or_helper_roots(env)
}

fn autofree_test_assert_not_release_eligible(env Environment, fn_key string, names []string) {
	assert fn_key in env.autofree_release_eligibility_by_fn_key
	assert fn_key in env.autofree_transfers_by_fn_key
	facts := env.autofree_release_eligibility_by_fn_key[fn_key]
	transfers := env.autofree_transfers_by_fn_key[fn_key]
	assert facts.len == names.len
	for fact in facts {
		transfer := autofree_test_transfer_by_to_name(transfers, fact.name)
		assert fact.fn_key == fn_key
		assert fact.eligibility == .not_release_eligible
		assert transfer.action != .move
		assert fact.fn_name == transfer.fn_name
		assert fact.transfer_kind == transfer.kind
		assert fact.transfer_action == transfer.action
		assert fact.state == transfer.to_endpoint.state
		assert fact.resource == transfer.to_endpoint.resource
		assert fact.shape.kind == transfer.to_endpoint.shape.kind
		assert fact.shape.identity == transfer.to_endpoint.shape.identity
		assert fact.shape.target_kind == transfer.to_endpoint.shape.target_kind
		assert fact.shape.target_identity == transfer.to_endpoint.shape.target_identity
		assert fact.shape.has_owned_resource == transfer.to_endpoint.shape.has_owned_resource
		assert fact.shape.may_need_free == transfer.to_endpoint.shape.may_need_free
		assert fact.shape.fail_closed == transfer.to_endpoint.shape.fail_closed
		assert fact.shape.map_container_may_need_free == transfer.to_endpoint.shape.map_container_may_need_free
		assert fact.shape.map_key_kind == transfer.to_endpoint.shape.map_key_kind
		assert fact.shape.map_key_may_need_free == transfer.to_endpoint.shape.map_key_may_need_free
		assert fact.shape.map_value_kind == transfer.to_endpoint.shape.map_value_kind
		assert fact.shape.map_value_may_need_free == transfer.to_endpoint.shape.map_value_may_need_free
		assert fact.endpoint.storage == transfer.to_endpoint.storage
		assert fact.endpoint.root_storage == transfer.to_endpoint.root_storage
		assert fact.endpoint.root_name == transfer.to_endpoint.root_name
		assert fact.endpoint.name == transfer.to_endpoint.name
		assert fact.endpoint.root_node_id == transfer.to_endpoint.root_node_id
		assert fact.endpoint.root_pos_id == transfer.to_endpoint.root_pos_id
		assert fact.endpoint.node_id == transfer.to_endpoint.node_id
		assert fact.endpoint.pos_id == transfer.to_endpoint.pos_id
		assert fact.endpoint.has_type == transfer.to_endpoint.has_type
		assert fact.endpoint.type_name == transfer.to_endpoint.type_name
		assert fact.endpoint.path.len == transfer.to_endpoint.path.len
		assert same_type_name(fact.endpoint.typ, transfer.to_endpoint.typ)
		assert fact.type_name == transfer.to_endpoint.type_name
		assert same_type_name(fact.typ, transfer.to_endpoint.typ)
	}
	for name in names {
		fact := autofree_test_release_eligibility_by_name(facts, name)
		assert fact.name == name
		assert fact.eligibility == .not_release_eligible
	}
	assert env.autofree_move_proofs_by_fn_key.len == 0
	assert env.autofree_release_preflights_by_fn_key.len == 0
	assert env.autofree_release_insertion_points_by_fn_key.len == 0
	autofree_test_assert_no_releases_or_helper_roots(env)
}

fn autofree_test_assert_only_transfer_to_a(env Environment, fn_name string) {
	assert fn_name in env.autofree_transfers_by_fn_key
	transfers := env.autofree_transfers_by_fn_key[fn_name]
	assert transfers.len == 1
	assert transfers[0].to_endpoint.name == 'a'
	autofree_test_assert_not_release_eligible(env, fn_name, ['a'])
}

fn autofree_test_holder_type(field_type Type) Type {
	return Type(Struct{
		name:   'Holder'
		fields: [
			Field{
				name: 'cached'
				typ:  field_type
			},
		]
	})
}

