fn autofree_test_assert_borrowed_pointer_loop_cursor_transfer(env Environment, flat ast.FlatAst, fn_key string, pointer_type Type, source_name string, cursor_name string) {
	source_param_id := autofree_test_node_id_by_kind_name_pos(flat, .aux_parameter, source_name,
		autofree_test_source_param_pos)
	source_use_id := autofree_test_node_id_by_kind_name_pos(flat, .expr_ident, source_name,
		autofree_test_rhs_pos)
	cursor_lhs_id := autofree_test_node_id_by_kind_name_pos(flat, .expr_ident, cursor_name,
		autofree_test_lhs_pos)
	post_lhs_id := autofree_test_node_id_by_kind_name_pos(flat, .expr_ident, cursor_name,
		autofree_test_post_lhs_pos)
	post_root_id := autofree_test_node_id_by_kind_name_pos(flat, .expr_ident, cursor_name,
		autofree_test_post_root_pos)
	post_selector_id := autofree_test_node_id_by_kind_pos(flat, .expr_selector,
		autofree_test_post_rhs_pos)
	assert fn_key in env.autofree_transfers_by_fn_key
	transfers := env.autofree_transfers_by_fn_key[fn_key]
	assert transfers.len == 1
	transfer := autofree_test_transfer_by_to_name(transfers, cursor_name)
	assert transfer.fn_key == fn_key
	assert transfer.fn_name == fn_key
	assert transfer.kind == .decl
	assert transfer.action == .borrow_no_free
	assert transfer.action != .move
	assert transfer.action != .clone_value
	assert transfer.from_name == source_name
	assert transfer.to_name == cursor_name
	assert transfer.from_endpoint.storage == .parameter
	assert transfer.from_endpoint.root_storage == .parameter
	assert transfer.from_endpoint.root_name == source_name
	assert transfer.from_endpoint.name == source_name
	assert transfer.from_endpoint.root_node_id == source_param_id
	assert transfer.from_endpoint.root_pos_id == autofree_test_source_param_pos
	assert transfer.from_endpoint.node_id == source_use_id
	assert transfer.from_endpoint.pos_id == autofree_test_rhs_pos
	assert transfer.from_endpoint.path.len == 0
	assert transfer.from_endpoint.has_type
	assert transfer.from_endpoint.resource == .pointer_value
	assert transfer.from_endpoint.shape.kind == .borrowed_pointer
	assert transfer.from_endpoint.state == .borrowed_no_free
	assert same_type_name(transfer.from_endpoint.typ, pointer_type)
	assert transfer.to_endpoint.storage == .local
	assert transfer.to_endpoint.root_storage == .local
	assert transfer.to_endpoint.root_name == cursor_name
	assert transfer.to_endpoint.name == cursor_name
	assert transfer.to_endpoint.root_node_id == cursor_lhs_id
	assert transfer.to_endpoint.root_pos_id == autofree_test_lhs_pos
	assert transfer.to_endpoint.node_id == cursor_lhs_id
	assert transfer.to_endpoint.pos_id == autofree_test_lhs_pos
	assert transfer.to_endpoint.path.len == 0
	assert transfer.to_endpoint.has_type
	assert transfer.to_endpoint.resource == .pointer_value
	assert transfer.to_endpoint.shape.kind == .borrowed_pointer
	assert transfer.to_endpoint.state == .borrowed_no_free
	assert same_type_name(transfer.to_endpoint.typ, pointer_type)
	assert transfer.shape.kind == .borrowed_pointer
	assert same_type_name(transfer.typ, pointer_type)
	assert post_lhs_id != ast.invalid_flat_node_id
	assert post_root_id != ast.invalid_flat_node_id
	assert post_selector_id != ast.invalid_flat_node_id
	assert env.autofree_fresh_locals_by_fn_key.len == 0
	assert fn_key in env.autofree_release_eligibility_by_fn_key
	facts := env.autofree_release_eligibility_by_fn_key[fn_key]
	assert facts.len == 1
	eligibility := autofree_test_release_eligibility_by_name(facts, cursor_name)
	assert eligibility.eligibility == .not_release_eligible
	assert eligibility.transfer_kind == .decl
	assert eligibility.transfer_action == .borrow_no_free
	assert eligibility.transfer_action != .move
	assert eligibility.transfer_action != .clone_value
	assert eligibility.endpoint.storage == .local
	assert eligibility.endpoint.root_storage == .local
	assert eligibility.endpoint.root_name == cursor_name
	assert eligibility.endpoint.name == cursor_name
	assert eligibility.endpoint.root_node_id == cursor_lhs_id
	assert eligibility.endpoint.root_pos_id == autofree_test_lhs_pos
	assert eligibility.endpoint.node_id == cursor_lhs_id
	assert eligibility.endpoint.pos_id == autofree_test_lhs_pos
	assert eligibility.endpoint.path.len == 0
	assert eligibility.endpoint.shape.kind == .borrowed_pointer
	assert eligibility.endpoint.state == .borrowed_no_free
	assert same_type_name(eligibility.endpoint.typ, pointer_type)
	autofree_test_assert_no_releases_or_helper_roots(env)
}

fn autofree_test_assert_no_borrowed_pointer_loop_cursor_or_releases(env Environment, cursor_name string) {
	for _, transfers in env.autofree_transfers_by_fn_key {
		for transfer in transfers {
			assert !(transfer.kind == .decl && transfer.action == .borrow_no_free
				&& transfer.to_name == cursor_name)
			assert transfer.action != .move
			assert transfer.action != .clone_value
		}
	}
	for _, facts in env.autofree_release_eligibility_by_fn_key {
		for fact in facts {
			assert !(fact.transfer_kind == .decl && fact.transfer_action == .borrow_no_free
				&& fact.name == cursor_name)
			assert fact.eligibility != .release_eligible
			assert fact.transfer_action != .move
			assert fact.transfer_action != .clone_value
		}
	}
	autofree_test_assert_no_releases_or_helper_roots(env)
}

