fn autofree_test_assert_no_prior_local_return_struct_literal_borrowed_pointer_field_initializer_or_releases(env Environment, field_name string) {
	for _, transfers in env.autofree_transfers_by_fn_key {
		for i, transfer in transfers {
			if i + 1 < transfers.len {
				next := transfers[i + 1]
				assert !(transfer.kind == .decl && next.kind == .struct_init
					&& next.action == .borrow_no_free && next.to_name == field_name
					&& next.to_endpoint.storage == .struct_field
					&& next.to_endpoint.root_storage == .return_value)
			}
			assert transfer.action != .move
			assert transfer.action != .clone_value
		}
	}
	for _, facts in env.autofree_release_eligibility_by_fn_key {
		for i, fact in facts {
			assert fact.eligibility != .release_eligible
			if i + 1 < facts.len {
				next := facts[i + 1]
				assert !(fact.transfer_kind == .decl && next.transfer_kind == .struct_init
					&& next.transfer_action == .borrow_no_free && next.name == field_name
					&& next.endpoint.storage == .struct_field
					&& next.endpoint.root_storage == .return_value)
			}
			assert fact.transfer_action != .move
			assert fact.transfer_action != .clone_value
		}
	}
	autofree_test_assert_no_releases_or_helper_roots(env)
}

fn autofree_test_struct_init_transfer_by_name(transfers []AutofreeTransferFact, name string) AutofreeTransferFact {
	for transfer in transfers {
		if transfer.kind == .struct_init && transfer.to_endpoint.name == name {
			return transfer
		}
	}
	assert false
	return AutofreeTransferFact{}
}

