	assert same_type_name(wrap_eligibility.typ, source_type)
	assert same_type_name(wrap_eligibility.endpoint.typ, source_type)
	return_eligibility := autofree_test_release_eligibility_by_name(facts, local_name)
	assert return_eligibility.eligibility == .not_release_eligible
	assert return_eligibility.transfer_kind == .return_expr
	assert return_eligibility.transfer_action == .ambiguous_no_free
	assert return_eligibility.transfer_action != .move
	assert return_eligibility.transfer_action != .clone_value
	assert return_eligibility.transfer_action != .borrow_no_free
	assert return_eligibility.transfer_action != .copy_no_resource
	assert return_eligibility.endpoint.storage == .return_value
	assert return_eligibility.endpoint.root_storage == .return_value
	assert return_eligibility.endpoint.name == local_name
	assert return_eligibility.endpoint.root_node_id == return_id
	assert return_eligibility.endpoint.root_pos_id == autofree_test_return_pos
	assert return_eligibility.endpoint.node_id == return_id
	assert return_eligibility.endpoint.pos_id == autofree_test_return_pos
	assert return_eligibility.endpoint.path.len == 0
	assert return_eligibility.endpoint.shape.kind == .struct_
	assert return_eligibility.endpoint.shape.needs_autofree()
	assert same_type_name(return_eligibility.typ, holder_type)
	assert same_type_name(return_eligibility.endpoint.typ, holder_type)
