fn autofree_test_assert_no_direct_sumtype_wrap_payload_or_releases(env Environment, variant_name string) {
	for _, transfers in env.autofree_transfers_by_fn_key {
		for transfer in transfers {
			assert !(transfer.kind == .sumtype_wrap && transfer.action == .ambiguous_no_free
				&& transfer.to_name == variant_name
				&& transfer.to_endpoint.storage == .sumtype_payload)
			assert transfer.action != .move
			assert transfer.action != .clone_value
			assert transfer.action != .borrow_no_free
			assert transfer.action != .copy_no_resource
		}
	}
	for _, facts in env.autofree_release_eligibility_by_fn_key {
		for fact in facts {
			assert fact.eligibility != .release_eligible
			assert !(fact.transfer_kind == .sumtype_wrap
				&& fact.transfer_action == .ambiguous_no_free && fact.name == variant_name
				&& fact.endpoint.storage == .sumtype_payload)
			assert fact.transfer_action != .move
			assert fact.transfer_action != .clone_value
			assert fact.transfer_action != .borrow_no_free
			assert fact.transfer_action != .copy_no_resource
		}
	}
	autofree_test_assert_no_releases_or_helper_roots(env)
}

