	return AutofreeTransferFact{}
}

fn autofree_test_release_eligibility_by_name(facts []AutofreeReleaseEligibilityFact, name string) AutofreeReleaseEligibilityFact {
	for fact in facts {
		if fact.name == name {
			return fact
		}
	}
	assert false
	return AutofreeReleaseEligibilityFact{}
}
